  // Generate grid 5 rows x 7 cols = 35 seats
  const seats = Array.from({ length: 35 }, (_, i) => i);

  // Map seat index to user
  const getStudentAtSeat = (index: number) => {
    return users.find(u => u.role === Role.STUDENT && u.seatIndex === index);
  };

  return (
