  </div>
);

const App = () => {
  return (
    <StoreProvider>
      <HashRouter>
        <Routes>
          <Route path="/login" element={<Login />} />

          <Route path="/" element={<Layout />}>
            <Route index element={<Navigate to="/dashboard" />} />
            <Route path="dashboard" element={<Dashboard />} />
            <Route path="assignments" element={<Assignments />} />
            <Route path="seating" element={<SeatingPlan />} />

            {/* Placeholder pages for completeness based on prompt */}
            <Route path="schedule" element={<SimplePage title="Class Schedule" />} />
            <Route path="videos" element={<SimplePage title="Video Materials" />} />
            <Route path="materials" element={<SimplePage title="Documents & Guides" />} />

