import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, Role, Announcement, Task, ScheduleItem, VideoMaterial, ActivityLog, Subject, DocumentMaterial, TutorEvent } from '../types';
import { generateUsers, initialAnnouncements, initialTasks, initialSchedule, initialVideos, initialSubjects, initialMaterials, initialTutorEvents } from '../services/mockData';

interface StoreContextType {
  currentUser: User | null;
  users: User[];
  subjects: Subject[];
  announcements: Announcement[];
  tasks: Task[];
  schedule: ScheduleItem[];
  videos: VideoMaterial[];
  materials: DocumentMaterial[];
  tutorEvents: TutorEvent[];
  activityLog: ActivityLog[];
  isDarkMode: boolean;

  toggleDarkMode: () => void;
  login: (username: string, password: string) => boolean;
  loginWithGoogle: (email: string, name: string, googleId: string) => void;
  logout: () => void;

  // Data manipulation
  addAnnouncement: (announcement: Announcement) => void;
  addTask: (task: Task) => void;
  toggleTaskCompletion: (taskId: string) => void;

  addSubject: (subject: Subject) => void;
  deleteSubject: (id: string) => void;

  addVideo: (video: VideoMaterial) => void;
  deleteVideo: (id: string) => void;

  addMaterial: (material: DocumentMaterial) => void;
  deleteMaterial: (id: string) => void;

  addTutorEvent: (event: TutorEvent) => void;
  deleteTutorEvent: (id: string) => void;
  joinTutorEvent: (eventId: string) => void;
  leaveTutorEvent: (eventId: string) => void;

  updateUserRole: (userId: string, role: Role) => void;
  updateUserStatus: (userId: string, isActive: boolean) => void;
  updateUserProfile: (userId: string, data: { fullName?: string, password?: string }) => void;

  updateSeat: (userId: string, seatIndex: number | null) => void;
  resetSeats: () => void;
  randomizeSeats: () => void;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider = ({ children }: { children?: ReactNode }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [subjects, setSubjects] = useState<Subject[]>(initialSubjects);
  const [announcements, setAnnouncements] = useState<Announcement[]>(initialAnnouncements);
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [schedule, setSchedule] = useState<ScheduleItem[]>(initialSchedule);
  const [videos, setVideos] = useState<VideoMaterial[]>(initialVideos);
  const [materials, setMaterials] = useState<DocumentMaterial[]>(initialMaterials);
  const [tutorEvents, setTutorEvents] = useState<TutorEvent[]>(initialTutorEvents);
  const [activityLog, setActivityLog] = useState<ActivityLog[]>([]);
  const [isDarkMode, setIsDarkMode] = useState<boolean>(true);

  // Initialize Data
  useEffect(() => {
    const storedUsers = localStorage.getItem('classSync_users');
    if (storedUsers) {
      setUsers(JSON.parse(storedUsers));
    } else {
      setUsers(generateUsers());
    }

    const storedSubjects = localStorage.getItem('classSync_subjects');
    if (storedSubjects) setSubjects(JSON.parse(storedSubjects));

    const storedVideos = localStorage.getItem('classSync_videos');
    if (storedVideos) setVideos(JSON.parse(storedVideos));

    const storedMaterials = localStorage.getItem('classSync_materials');
    if (storedMaterials) setMaterials(JSON.parse(storedMaterials));

    const storedTutorEvents = localStorage.getItem('classSync_tutorEvents');
    if (storedTutorEvents) setTutorEvents(JSON.parse(storedTutorEvents));
  }, []);

  // Persist Data Changes
  useEffect(() => {
    if (users.length > 0) localStorage.setItem('classSync_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    localStorage.setItem('classSync_subjects', JSON.stringify(subjects));
  }, [subjects]);

  useEffect(() => {
    localStorage.setItem('classSync_videos', JSON.stringify(videos));
  }, [videos]);

  useEffect(() => {
    localStorage.setItem('classSync_materials', JSON.stringify(materials));
  }, [materials]);

  useEffect(() => {
    localStorage.setItem('classSync_tutorEvents', JSON.stringify(tutorEvents));
  }, [tutorEvents]);

  // Dark Mode
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  const logActivity = (action: string) => {
    if (!currentUser) return;
    const log: ActivityLog = {
      id: Date.now().toString(),
      userId: currentUser.id,
      action: `${currentUser.username} (${currentUser.role}): ${action}`,
      timestamp: new Date().toISOString()
    };
    setActivityLog(prev => [log, ...prev]);
  };

  const login = (u: string, p: string) => {
    const user = users.find(usr => usr.username === u && usr.password === p);
    if (user && user.isActive) {
      setCurrentUser(user);
      logActivity(`Logged in`);
      return true;
    }
    return false;
  };

  const loginWithGoogle = (email: string, name: string, googleId: string) => {
    let user = users.find(u => u.username === email);

    if (!user) {
      user = {
        id: `g_${googleId}`,
        username: email,
        fullName: name,
        role: Role.STUDENT, 
        isActive: true,
        password: '', 
        seatIndex: null
      };
      setUsers(prev => [...prev, user!]);
    }

    if (user && user.isActive) {
      setCurrentUser(user);
      logActivity(`Logged in via Google`);
    }
  };

  const logout = () => {
    logActivity(`Logged out`);
    setCurrentUser(null);
  };

  // --- Actions ---

  const addAnnouncement = (item: Announcement) => {
    setAnnouncements([item, ...announcements]);
    logActivity(`Added announcement: ${item.title}`);
  };

  const addTask = (item: Task) => {
    setTasks([item, ...tasks]);
    logActivity(`Added task: ${item.title}`);
  };

  const toggleTaskCompletion = (taskId: string) => {
     setTasks(tasks.map(t => t.id === taskId ? { ...t, isCompleted: !t.isCompleted } : t));
  };

  const addSubject = (subject: Subject) => {
    setSubjects([...subjects, subject]);
    logActivity(`Added subject: ${subject.name}`);
  }

  const deleteSubject = (id: string) => {
    setSubjects(subjects.filter(s => s.id !== id));
    logActivity(`Deleted subject ID: ${id}`);
  }

  const addVideo = (video: VideoMaterial) => {
    setVideos([video, ...videos]);
    logActivity(`Added video: ${video.title}`);
  }

  const deleteVideo = (id: string) => {
    setVideos(videos.filter(v => v.id !== id));
    logActivity(`Deleted video ID: ${id}`);
  }

  const addMaterial = (material: DocumentMaterial) => {
    setMaterials([material, ...materials]);
    logActivity(`Added material: ${material.title}`);
  }

  const deleteMaterial = (id: string) => {
    setMaterials(materials.filter(m => m.id !== id));
    logActivity(`Deleted material ID: ${id}`);
  }

  const addTutorEvent = (event: TutorEvent) => {
    setTutorEvents([event, ...tutorEvents]);
    logActivity(`Added tutor event: ${event.title}`);
  };

  const deleteTutorEvent = (id: string) => {
    setTutorEvents(tutorEvents.filter(e => e.id !== id));
    logActivity(`Deleted tutor event ID: ${id}`);
  };

  const joinTutorEvent = (eventId: string) => {
    if (!currentUser) return;
    setTutorEvents(prev => prev.map(ev => {
      if (ev.id === eventId && ev.participants.length < ev.maxParticipants && !ev.participants.includes(currentUser.id)) {
        return { ...ev, participants: [...ev.participants, currentUser.id] };
      }
      return ev;
    }));
    logActivity(`Joined tutor event ID: ${eventId}`);
  };

  const leaveTutorEvent = (eventId: string) => {
    if (!currentUser) return;
    setTutorEvents(prev => prev.map(ev => {
      if (ev.id === eventId) {
        return { ...ev, participants: ev.participants.filter(id => id !== currentUser.id) };
      }
      return ev;
    }));
    logActivity(`Left tutor event ID: ${eventId}`);
  };

  const updateUserRole = (userId: string, role: Role) => {
    setUsers(users.map(u => u.id === userId ? { ...u, role } : u));
    logActivity(`Updated user ${userId} to role ${role}`);
  };

  const updateUserStatus = (userId: string, isActive: boolean) => {
    setUsers(users.map(u => u.id === userId ? { ...u, isActive } : u));
    logActivity(`Updated user ${userId} active status to ${isActive}`);
  };

  const updateUserProfile = (userId: string, data: { fullName?: string, password?: string }) => {
    setUsers(users.map(u => {
      if (u.id === userId) {
        return { 
          ...u, 
          fullName: data.fullName || u.fullName,
          password: data.password || u.password
        };
      }
      return u;
    }));
    if (currentUser && currentUser.id === userId) {
      setCurrentUser(prev => prev ? {
        ...prev,
        fullName: data.fullName || prev.fullName,
        password: data.password || prev.password
      } : null);
    }
    logActivity(`User ${userId} updated their profile`);
  };

  const updateSeat = (userId: string, seatIndex: number | null) => {
    setUsers(prev => prev.map(u => {
      if (u.id === userId) {
        return { ...u, seatIndex };
      }
      if (seatIndex !== null && u.seatIndex === seatIndex) {
        return { ...u, seatIndex: null };
      }
      return u;
    }));
    logActivity(`Updated seat for user ${userId}`);
  };

  const resetSeats = () => {
     setUsers(prev => prev.map(u => ({ ...u, seatIndex: null })));
     logActivity('Reset all seats');
  };

  const randomizeSeats = () => {
    const studentIds = users.filter(u => u.role === Role.STUDENT).map(u => u.id);
    const shuffled = [...studentIds].sort(() => Math.random() - 0.5);

    setUsers(prev => prev.map(u => {
      if (u.role === Role.STUDENT) {
        const idx = shuffled.indexOf(u.id);
        return { ...u, seatIndex: idx < 35 ? idx : null }; 
      }
      return u;
    }));
    logActivity('Randomized seats');
  };

  return (
    <StoreContext.Provider value={{
      currentUser, users, subjects, announcements, tasks, schedule, videos, materials, tutorEvents, activityLog, isDarkMode,
      toggleDarkMode, login, loginWithGoogle, logout, 
      addAnnouncement, addTask, toggleTaskCompletion,
      addSubject, deleteSubject,
      addVideo, deleteVideo,
      addMaterial, deleteMaterial,
      addTutorEvent, deleteTutorEvent, joinTutorEvent, leaveTutorEvent,
      updateUserRole, updateUserStatus, updateUserProfile,
      updateSeat, resetSeats, randomizeSeats
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error("useStore must be used within StoreProvider");
  return context;
};

