import React, { useState, useRef } from 'react';
import { useStore } from '../context/Store';
import { Role, DocumentMaterial } from '../types';
import { FileText, Plus, Trash2, Download, File, Eye, X, Maximize2, ExternalLink } from 'lucide-react';

export const Materials = () => {
  const { materials, subjects, currentUser, addMaterial, deleteMaterial } = useStore();
  const [showModal, setShowModal] = useState(false);
  const [filterSubject, setFilterSubject] = useState('ALL');

  // Viewer State
  const [viewingDoc, setViewingDoc] = useState<DocumentMaterial | null>(null);
  const viewerRef = useRef<HTMLDivElement>(null);

  const [newDoc, setNewDoc] = useState({ title: '', url: '', description: '', subject: '', type: 'PDF' as const });

  const canAdd = [Role.SEKRETARIS, Role.KURIKULUM, Role.ADMIN].includes(currentUser?.role as Role);

  const formatUrl = (url: string) => {
    // Transform Google Drive links to preview mode to avoid "View" permission errors in iframe
    // Case: /view, /edit -> /preview
    if (url.includes('drive.google.com') && (url.includes('/view') || url.includes('/edit'))) {
       return url.replace(/\/view.*|\/edit.*/, '/preview');
    }
    return url;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    addMaterial({
      id: Date.now().toString(),
      ...newDoc,
      url: formatUrl(newDoc.url),
      uploadedBy: currentUser.role
    });
    setShowModal(false);
    setNewDoc({ title: '', url: '', description: '', subject: '', type: 'PDF' });
  };

  const handleView = (doc: DocumentMaterial) => {
    if (!doc.url || doc.url === '#' || doc.url.trim() === '') {
      alert("Invalid document URL.");
      return;
    }
    setViewingDoc(doc);
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement && viewerRef.current) {
      viewerRef.current.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable full-screen mode: ${err.message} (${err.name})`);
      });
    } else {
      if (document.fullscreenElement) {
        document.exitFullscreen();
      }
    }
  };

  const filteredMaterials = filterSubject === 'ALL' 
    ? materials 
    : materials.filter(m => m.subject === filterSubject);

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
          <FileText /> Documents & Guides
        </h1>
        {canAdd && (
          <button 
            onClick={() => setShowModal(true)}
            className="bg-primary text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-600"
          >
            <Plus size={18} /> Add Material
          </button>
        )}
      </div>

      <div className="mb-6">
        <select 
          value={filterSubject}
          onChange={(e) => setFilterSubject(e.target.value)}
          className="p-2 border rounded-lg bg-white dark:bg-gray-800 dark:text-white dark:border-gray-700"
        >
          <option value="ALL">All Subjects</option>
          {subjects.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
        </select>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {filteredMaterials.map(doc => (
          <div key={doc.id} className="bg-white dark:bg-gray-800 p-5 rounded-lg shadow-sm border border-gray-100 dark:border-gray-700 flex items-start justify-between group">
            <div className="flex gap-4">
              <div className="bg-red-50 text-red-500 p-3 rounded-lg dark:bg-red-900/20">
                 <File size={24} />
              </div>
              <div>
                <a 
                  href={doc.url} 
                  target="_blank" 
                  rel="noreferrer"
                  className="font-bold text-gray-900 dark:text-white hover:text-primary hover:underline"
                >
                  {doc.title}
                </a>
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">{doc.description}</p>
                <div className="flex gap-3 mt-2 text-xs font-medium">
                   <span className="text-primary bg-blue-50 dark:bg-blue-900/30 px-2 py-0.5 rounded">{doc.subject}</span>
                   <span className="text-gray-400 uppercase">{doc.type}</span>
                </div>
              </div>
            </div>
            <div className="flex gap-2">
               {/* View Button for PDFs */}
               {doc.type === 'PDF' && (
                 <button 
                   onClick={() => handleView(doc)} 
                   className="text-gray-400 hover:text-primary p-1"
                   title="Preview Document"
                 >
                   <Eye size={18} />
                 </button>
               )}

               <a href={doc.url} target="_blank" rel="noreferrer" className="text-gray-400 hover:text-primary p-1" title="Download / Open Link">
                 <Download size={18} />
               </a>

               {canAdd && (
                  <button onClick={() => deleteMaterial(doc.id)} className="text-gray-400 hover:text-red-500 p-1" title="Delete">
                    <Trash2 size={18} />
                  </button>
               )}
            </div>
          </div>
        ))}
      </div>

      {filteredMaterials.length === 0 && (
        <div className="text-center py-12 text-gray-400">No documents found.</div>
      )}

      {/* PDF Viewer Modal */}
      {viewingDoc && (
        <div ref={viewerRef} className="fixed inset-0 z-50 bg-gray-900 flex flex-col animate-fade-in">
          {/* Viewer Toolbar */}
          <div className="flex justify-between items-center px-6 py-3 bg-gray-800 border-b border-gray-700 text-white shadow-md">
             <div className="flex items-center gap-3">
               <FileText size={20} className="text-primary" />
               <h3 className="font-semibold truncate max-w-md">{viewingDoc.title}</h3>
             </div>
             <div className="flex items-center gap-4">
                <a 
                   href={viewingDoc.url} 
                   target="_blank" 
                   rel="noreferrer"
                   className="px-3 py-1 bg-gray-700 hover:bg-gray-600 rounded text-sm text-white flex items-center gap-2"
                >
                   <ExternalLink size={16} /> Open in New Tab
                </a>
                <button 
                  onClick={toggleFullScreen}
                  className="p-2 hover:bg-gray-700 rounded-full transition-colors text-gray-300 hover:text-white"
                  title="Toggle Full Screen"
                >
                  <Maximize2 size={20} />
                </button>
                <button 
                  onClick={() => setViewingDoc(null)}
                  className="p-2 hover:bg-red-500/20 hover:text-red-500 rounded-full transition-colors text-gray-300"
                  title="Close Viewer"
                >
                  <X size={24} />
                </button>
             </div>
          </div>

          {/* Viewer Content */}
          <div className="flex-1 bg-gray-200 dark:bg-gray-900 relative flex items-center justify-center">
             <iframe 
               src={viewingDoc.url} 
               className="w-full h-full border-0"
               title={viewingDoc.title}
             />
             <div className="absolute -z-10 text-gray-500 text-center p-4">
                <p>Loading document...</p>
                <p className="text-sm mt-2">If content does not appear, use the "Open in New Tab" button.</p>
             </div>
          </div>
        </div>
      )}

      {/* Add Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white dark:bg-gray-800 p-6 rounded-lg w-full max-w-md">
            <h3 className="text-xl font-bold mb-4 dark:text-white">Add Document</h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <input 
                className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                placeholder="Document Title"
                required
                value={newDoc.title}
                onChange={e => setNewDoc({...newDoc, title: e.target.value})}
              />
              <textarea 
                className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                placeholder="Description"
                required
                value={newDoc.description}
                onChange={e => setNewDoc({...newDoc, description: e.target.value})}
              />
              <div className="space-y-1">
                 <input 
                  className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                  placeholder="File URL / Drive Link"
                  required
                  value={newDoc.url}
                  onChange={e => setNewDoc({...newDoc, url: e.target.value})}
                />
                <p className="text-xs text-gray-400">For Google Drive, ensure "Anyone with the link" is selected.</p>
              </div>
              <select 
                className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                required
                value={newDoc.subject}
                onChange={e => setNewDoc({...newDoc, subject: e.target.value})}
              >
                <option value="">Select Subject</option>
                {subjects.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
              </select>
               <select 
                className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                value={newDoc.type}
                onChange={(e: any) => setNewDoc({...newDoc, type: e.target.value})}
              >
                <option value="PDF">PDF</option>
                <option value="DOC">DOC</option>
              </select>
              <div className="flex justify-end gap-2">
                <button type="button" onClick={() => setShowModal(false)} className="px-4 py-2 text-gray-500">Cancel</button>
                <button type="submit" className="px-4 py-2 bg-primary text-white rounded">Save</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, Role, Announcement, Task, ScheduleItem, VideoMaterial, ActivityLog, Subject, DocumentMaterial, TutorEvent } from '../types';
import { generateUsers, initialAnnouncements, initialTasks, initialSchedule, initialVideos, initialSubjects, initialMaterials, initialTutorEvents } from '../services/mockData';

interface StoreContextType {
  currentUser: User | null;
  users: User[];
  subjects: Subject[];
  announcements: Announcement[];
  tasks: Task[];
  schedule: ScheduleItem[];
  videos: VideoMaterial[];
  materials: DocumentMaterial[];
  tutorEvents: TutorEvent[];
  activityLog: ActivityLog[];
  isDarkMode: boolean;

  toggleDarkMode: () => void;
  login: (username: string, password: string) => boolean;
  loginWithGoogle: (email: string, name: string, googleId: string) => void;
  logout: () => void;

  // Data manipulation
  addAnnouncement: (announcement: Announcement) => void;
  addTask: (task: Task) => void;
  toggleTaskCompletion: (taskId: string) => void;

  addSubject: (subject: Subject) => void;
  deleteSubject: (id: string) => void;

  addScheduleItem: (item: ScheduleItem) => void;
  deleteScheduleItem: (id: string) => void;

  addVideo: (video: VideoMaterial) => void;
  deleteVideo: (id: string) => void;

  addMaterial: (material: DocumentMaterial) => void;
  deleteMaterial: (id: string) => void;

  addTutorEvent: (event: TutorEvent) => void;
  deleteTutorEvent: (id: string) => void;
  joinTutorEvent: (eventId: string) => void;
  leaveTutorEvent: (eventId: string) => void;

  updateUserRole: (userId: string, role: Role) => void;
  updateUserStatus: (userId: string, isActive: boolean) => void;
  updateUserProfile: (userId: string, data: { fullName?: string, password?: string }) => void;

  updateSeat: (userId: string, seatIndex: number | null) => void;
  resetSeats: () => void;
  randomizeSeats: () => void;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider = ({ children }: { children?: ReactNode }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [subjects, setSubjects] = useState<Subject[]>(initialSubjects);
  const [announcements, setAnnouncements] = useState<Announcement[]>(initialAnnouncements);
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [schedule, setSchedule] = useState<ScheduleItem[]>(initialSchedule);
  const [videos, setVideos] = useState<VideoMaterial[]>(initialVideos);
  const [materials, setMaterials] = useState<DocumentMaterial[]>(initialMaterials);
  const [tutorEvents, setTutorEvents] = useState<TutorEvent[]>(initialTutorEvents);
  const [activityLog, setActivityLog] = useState<ActivityLog[]>([]);
  const [isDarkMode, setIsDarkMode] = useState<boolean>(true);

  // Initialize Data
  useEffect(() => {
    const storedUsers = localStorage.getItem('classSync_users');
    if (storedUsers) {
      setUsers(JSON.parse(storedUsers));
    } else {
      setUsers(generateUsers());
    }

    const storedSubjects = localStorage.getItem('classSync_subjects');
    if (storedSubjects) setSubjects(JSON.parse(storedSubjects));

    const storedSchedule = localStorage.getItem('classSync_schedule');
    if (storedSchedule) setSchedule(JSON.parse(storedSchedule));

    const storedVideos = localStorage.getItem('classSync_videos');
    if (storedVideos) setVideos(JSON.parse(storedVideos));

    const storedMaterials = localStorage.getItem('classSync_materials');
    if (storedMaterials) setMaterials(JSON.parse(storedMaterials));

    const storedTutorEvents = localStorage.getItem('classSync_tutorEvents');
    if (storedTutorEvents) setTutorEvents(JSON.parse(storedTutorEvents));
  }, []);

  // Persist Data Changes
  useEffect(() => {
    if (users.length > 0) localStorage.setItem('classSync_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    localStorage.setItem('classSync_subjects', JSON.stringify(subjects));
  }, [subjects]);

  useEffect(() => {
    localStorage.setItem('classSync_schedule', JSON.stringify(schedule));
  }, [schedule]);

  useEffect(() => {
    localStorage.setItem('classSync_videos', JSON.stringify(videos));
  }, [videos]);

  useEffect(() => {
    localStorage.setItem('classSync_materials', JSON.stringify(materials));
  }, [materials]);

  useEffect(() => {
    localStorage.setItem('classSync_tutorEvents', JSON.stringify(tutorEvents));
  }, [tutorEvents]);

  // Dark Mode
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  const logActivity = (action: string) => {
    if (!currentUser) return;
    const log: ActivityLog = {
      id: Date.now().toString(),
      userId: currentUser.id,
      action: `${currentUser.username} (${currentUser.role}): ${action}`,
      timestamp: new Date().toISOString()
    };
    setActivityLog(prev => [log, ...prev]);
  };

  const login = (u: string, p: string) => {
    const user = users.find(usr => usr.username === u && usr.password === p);
    if (user && user.isActive) {
      setCurrentUser(user);
      logActivity(`Logged in`);
      return true;
    }
    return false;
  };

  const loginWithGoogle = (email: string, name: string, googleId: string) => {
    let user = users.find(u => u.username === email);

    if (!user) {
      user = {
        id: `g_${googleId}`,
        username: email,
        fullName: name,
        role: Role.STUDENT, 
        isActive: true,
        password: '', 
        seatIndex: null
      };
      setUsers(prev => [...prev, user!]);
    }

    if (user && user.isActive) {
      setCurrentUser(user);
      logActivity(`Logged in via Google`);
    }
  };

  const logout = () => {
    logActivity(`Logged out`);
    setCurrentUser(null);
  };

  // --- Actions ---

  const addAnnouncement = (item: Announcement) => {
    setAnnouncements([item, ...announcements]);
    logActivity(`Added announcement: ${item.title}`);
  };

  const addTask = (item: Task) => {
    setTasks([item, ...tasks]);
    logActivity(`Added task: ${item.title}`);
  };

  const toggleTaskCompletion = (taskId: string) => {
     setTasks(tasks.map(t => t.id === taskId ? { ...t, isCompleted: !t.isCompleted } : t));
  };

  const addSubject = (subject: Subject) => {
    setSubjects([...subjects, subject]);
    logActivity(`Added subject: ${subject.name}`);
  }

  const deleteSubject = (id: string) => {
    setSubjects(subjects.filter(s => s.id !== id));
    logActivity(`Deleted subject ID: ${id}`);
  }

  const addScheduleItem = (item: ScheduleItem) => {
    setSchedule([...schedule, item]);
    logActivity(`Added schedule item for ${item.day}`);
  }

  const deleteScheduleItem = (id: string) => {
    setSchedule(schedule.filter(s => s.id !== id));
    logActivity(`Deleted schedule item ID: ${id}`);
  }

  const addVideo = (video: VideoMaterial) => {
    setVideos([video, ...videos]);
    logActivity(`Added video: ${video.title}`);
  }

  const deleteVideo = (id: string) => {
    setVideos(videos.filter(v => v.id !== id));
    logActivity(`Deleted video ID: ${id}`);
  }

  const addMaterial = (material: DocumentMaterial) => {
    setMaterials([material, ...materials]);
    logActivity(`Added material: ${material.title}`);
  }

  const deleteMaterial = (id: string) => {
    setMaterials(materials.filter(m => m.id !== id));
    logActivity(`Deleted material ID: ${id}`);
  }

  const addTutorEvent = (event: TutorEvent) => {
    setTutorEvents([event, ...tutorEvents]);
    logActivity(`Added tutor event: ${event.title}`);
  };

  const deleteTutorEvent = (id: string) => {
    setTutorEvents(tutorEvents.filter(e => e.id !== id));
    logActivity(`Deleted tutor event ID: ${id}`);
  };

  const joinTutorEvent = (eventId: string) => {
    if (!currentUser) return;
    setTutorEvents(prev => prev.map(ev => {
      if (ev.id === eventId && ev.participants.length < ev.maxParticipants && !ev.participants.includes(currentUser.id)) {
        return { ...ev, participants: [...ev.participants, currentUser.id] };
      }
      return ev;
    }));
    logActivity(`Joined tutor event ID: ${eventId}`);
  };

  const leaveTutorEvent = (eventId: string) => {
    if (!currentUser) return;
    setTutorEvents(prev => prev.map(ev => {
      if (ev.id === eventId) {
        return { ...ev, participants: ev.participants.filter(id => id !== currentUser.id) };
      }
      return ev;
    }));
    logActivity(`Left tutor event ID: ${eventId}`);
  };

  const updateUserRole = (userId: string, role: Role) => {
    setUsers(users.map(u => u.id === userId ? { ...u, role } : u));
    logActivity(`Updated user ${userId} to role ${role}`);
  };

  const updateUserStatus = (userId: string, isActive: boolean) => {
    setUsers(users.map(u => u.id === userId ? { ...u, isActive } : u));
    logActivity(`Updated user ${userId} active status to ${isActive}`);
  };

  const updateUserProfile = (userId: string, data: { fullName?: string, password?: string }) => {
    setUsers(users.map(u => {
      if (u.id === userId) {
        return { 
          ...u, 
          fullName: data.fullName || u.fullName,
          password: data.password || u.password
        };
      }
      return u;
    }));
    if (currentUser && currentUser.id === userId) {
      setCurrentUser(prev => prev ? {
        ...prev,
        fullName: data.fullName || prev.fullName,
        password: data.password || prev.password
      } : null);
    }
    logActivity(`User ${userId} updated their profile`);
  };

  const updateSeat = (userId: string, seatIndex: number | null) => {
    setUsers(prev => prev.map(u => {
      if (u.id === userId) {
        return { ...u, seatIndex };
      }
      if (seatIndex !== null && u.seatIndex === seatIndex) {
        return { ...u, seatIndex: null };
      }
      return u;
    }));
    logActivity(`Updated seat for user ${userId}`);
  };

  const resetSeats = () => {
     setUsers(prev => prev.map(u => ({ ...u, seatIndex: null })));
     logActivity('Reset all seats');
  };

  const randomizeSeats = () => {
    const studentIds = users.filter(u => u.role === Role.STUDENT).map(u => u.id);
    const shuffled = [...studentIds].sort(() => Math.random() - 0.5);

    setUsers(prev => prev.map(u => {
      if (u.role === Role.STUDENT) {
        const idx = shuffled.indexOf(u.id);
        return { ...u, seatIndex: idx < 35 ? idx : null }; 
      }
      return u;
    }));
    logActivity('Randomized seats');
  };

  return (
    <StoreContext.Provider value={{
      currentUser, users, subjects, announcements, tasks, schedule, videos, materials, tutorEvents, activityLog, isDarkMode,
      toggleDarkMode, login, loginWithGoogle, logout, 
      addAnnouncement, addTask, toggleTaskCompletion,
      addSubject, deleteSubject, addScheduleItem, deleteScheduleItem,
      addVideo, deleteVideo,
      addMaterial, deleteMaterial,
      addTutorEvent, deleteTutorEvent, joinTutorEvent, leaveTutorEvent,
      updateUserRole, updateUserStatus, updateUserProfile,
      updateSeat, resetSeats, randomizeSeats
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error("useStore must be used within StoreProvider");
  return context;
};

import React, { useState } from 'react';
import { useStore } from '../context/Store';
import { Role } from '../types';
import { Calendar, Plus, Clock, MapPin, Trash2, BookOpen } from 'lucide-react';

const DAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'];

export const Schedule = () => {
  const { schedule, subjects, currentUser, addScheduleItem, deleteScheduleItem } = useStore();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newItem, setNewItem] = useState({
    day: 'Monday',
    startTime: '',
    endTime: '',
    subject: '',
    room: ''
  });

  const canManage = [Role.ADMIN, Role.KURIKULUM].includes(currentUser?.role as Role);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItem.subject) return;

    addScheduleItem({
      id: Date.now().toString(),
      day: newItem.day,
      time: `${newItem.startTime} - ${newItem.endTime}`,
      subject: newItem.subject,
      room: newItem.room
    });
    setIsModalOpen(false);
    setNewItem({ day: 'Monday', startTime: '', endTime: '', subject: '', room: '' });
  };

  // Helper to find subject details (like teacher, code) based on name
  const getSubjectDetails = (name: string) => subjects.find(s => s.name === name);

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <Calendar /> Class Schedule
          </h1>
          <p className="text-gray-500 dark:text-gray-400 mt-1">
             Weekly fixed schedule for the semester.
          </p>
        </div>
        {canManage && (
          <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-primary text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-600 shadow-md transition"
          >
            <Plus size={18} /> Add Class
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-6">
        {DAYS.map(day => {
          // Get items for this day and sort by start time (simple string comparison works for HH:MM 24h format)
          const dayItems = schedule
            .filter(s => s.day === day)
            .sort((a, b) => a.time.localeCompare(b.time));

          return (
            <div key={day} className="flex flex-col gap-4">
              <div className="bg-gray-100 dark:bg-gray-800 p-3 rounded-lg text-center font-bold text-gray-700 dark:text-gray-200 border-b-4 border-primary/50 shadow-sm">
                {day}
              </div>

              <div className="space-y-4">
                {dayItems.length === 0 ? (
                  <div className="text-center py-8 text-gray-400 text-sm border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-lg">
                    Free Day
                  </div>
