  ADMIN = 'ADMIN',
  STUDENT = 'STUDENT',
  KURIKULUM = 'KURIKULUM',
  KOMTI = 'KOMTI',
  WAKOMTI = 'WAKOMTI',
  IT_LOGISTIK = 'IT_LOGISTIK',
  TATA_TERTIB = 'TATA_TERTIB',
  SEKRETARIS = 'SEKRETARIS',
