  id: string;
  username: string;
  fullName: string;
  role: Role;
  password?: string; // In a real app, never store plain password
  isActive: boolean;
  seatIndex?: number | null; // For seating plan (0-34)
}

export interface Subject {
  id: string;
  name: string;
  code: string;
  teacher?: string;
}

export interface Announcement {
  id: string;
  title: string;
  content: string;
  date: string;
  authorId: string;
  authorName: string;
  type: 'NORMAL' | 'IMPORTANT' | 'EMERGENCY';
}

