  id: string;
  title: string;
  description: string;
  subject: string; // Should match Subject.name or ID
  deadline: string;
  isCompleted: boolean; // For student view toggling locally
  createdBy: Role;
}

export interface ScheduleItem {
  id: string;
  day: string; // "Monday", etc.
  time: string;
  subject: string;
  room: string;
}

export interface VideoMaterial {
  id: string;
  title: string;
  url: string; // YouTube or Drive link
  subject: string;
  week: number;
  uploadedBy: string;
}

export interface DocumentMaterial {
  id: string;
  title: string;
  type: 'PDF' | 'DOC';
  url: string;
  description: string;
  subject: string;
  uploadedBy: string;
}

export interface TutorEvent {
  id: string;
  title: string;
  description: string;
  date: string;
  tutorId: string;
  tutorName: string;
  maxParticipants: number;
  participants: string[]; // List of User IDs who joined
  waitingList: string[]; // List of User IDs in waiting list
}

// Log activity
export interface ActivityLog {
  id: string;
  userId: string;
  action: string;
  timestamp: string;
}

