import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, Role, Announcement, Task, ScheduleItem, VideoMaterial, ActivityLog, Subject, DocumentMaterial, TutorEvent } from '../types';
import { generateUsers, initialAnnouncements, initialTasks, initialSchedule, initialVideos, initialSubjects, initialMaterials, initialTutorEvents } from '../services/mockData';
import { supabase, isSupabaseConfigured } from '../services/supabaseClient';

interface StoreContextType {
  currentUser: User | null;
  users: User[];
  subjects: Subject[];
  announcements: Announcement[];
  tasks: Task[];
  schedule: ScheduleItem[];
  videos: VideoMaterial[];
  materials: DocumentMaterial[];
  tutorEvents: TutorEvent[];
  activityLog: ActivityLog[];
  isDarkMode: boolean;
  isLoading: boolean;

  toggleDarkMode: () => void;
  login: (username: string, password: string) => boolean;
  loginWithGoogle: (email: string, name: string, googleId: string) => void;
  logout: () => void;

  // Data manipulation
  addAnnouncement: (announcement: Announcement) => void;
  addTask: (task: Task) => void;
  toggleTaskCompletion: (taskId: string) => void;

  addSubject: (subject: Subject) => void;
  deleteSubject: (id: string) => void;

  addScheduleItem: (item: ScheduleItem) => void;
  deleteScheduleItem: (id: string) => void;

  addVideo: (video: VideoMaterial) => void;
  deleteVideo: (id: string) => void;

  addMaterial: (material: DocumentMaterial) => void;
  deleteMaterial: (id: string) => void;

  addTutorEvent: (event: TutorEvent) => void;
  editTutorEvent: (id: string, updates: Partial<TutorEvent>) => void;
  deleteTutorEvent: (id: string) => void;
  joinTutorEvent: (eventId: string) => void;
  leaveTutorEvent: (eventId: string) => void;
  promoteFromWaitingList: (eventId: string, userId: string) => void;

  updateUserRole: (userId: string, role: Role) => void;
  updateUserStatus: (userId: string, isActive: boolean) => void;
  updateUserProfile: (userId: string, data: { fullName?: string, password?: string }) => void;

  updateSeat: (userId: string, seatIndex: number | null) => void;
  resetSeats: () => void;
  randomizeSeats: () => void;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider = ({ children }: { children?: ReactNode }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Data States
  const [users, setUsers] = useState<User[]>([]);
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [schedule, setSchedule] = useState<ScheduleItem[]>([]);
  const [videos, setVideos] = useState<VideoMaterial[]>([]);
  const [materials, setMaterials] = useState<DocumentMaterial[]>([]);
  const [tutorEvents, setTutorEvents] = useState<TutorEvent[]>([]);
  const [activityLog, setActivityLog] = useState<ActivityLog[]>([]);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  // --- Initial Data Fetching ---
  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);

      // 1. Check if Supabase is configured
      if (!isSupabaseConfigured()) {
        console.warn("Supabase credentials missing. Falling back to local/mock data.");
        loadLocalData();
        setIsLoading(false);
        return;
      }

      try {
        // 2. Fetch Users
        const { data: dbUsers, error: userError } = await supabase.from('users').select('*');
        if (dbUsers && dbUsers.length > 0) {
          setUsers(dbUsers);
        } else {
          // Seed initial users if DB is empty
          const seedUsers = generateUsers();
          await supabase.from('users').insert(seedUsers);
          setUsers(seedUsers);
        }

        // 3. Fetch Subjects
        const { data: dbSubjects } = await supabase.from('subjects').select('*');
        setSubjects(dbSubjects?.length ? dbSubjects : []);

        // 4. Fetch Announcements
        const { data: dbAnnounce } = await supabase.from('announcements').select('*').order('date', { ascending: false });
        setAnnouncements(dbAnnounce?.length ? dbAnnounce : []);

        // 5. Fetch Tasks
        const { data: dbTasks } = await supabase.from('tasks').select('*').order('deadline', { ascending: true });
        setTasks(dbTasks?.length ? dbTasks : []);

        // 6. Fetch Schedule
        const { data: dbSchedule } = await supabase.from('schedule').select('*');
        setSchedule(dbSchedule?.length ? dbSchedule : []);

        // 7. Fetch Videos
        const { data: dbVideos } = await supabase.from('videos').select('*');
        setVideos(dbVideos?.length ? dbVideos : []);

        // 8. Fetch Materials
        const { data: dbMaterials } = await supabase.from('materials').select('*');
        setMaterials(dbMaterials?.length ? dbMaterials : []);

        // 9. Fetch Tutor Events
        const { data: dbEvents } = await supabase.from('tutor_events').select('*');
        setTutorEvents(dbEvents?.length ? dbEvents : []);

        // 10. Fetch Logs
        const { data: dbLogs } = await supabase.from('activity_logs').select('*').order('timestamp', { ascending: false }).limit(50);
        setActivityLog(dbLogs?.length ? dbLogs : []);

      } catch (error) {
        console.error("Error fetching data from Supabase:", error);
        loadLocalData(); // Fallback on error
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  const loadLocalData = () => {
    // Fallback logic from previous version
    const storedUsers = localStorage.getItem('classSync_users');
    setUsers(storedUsers ? JSON.parse(storedUsers) : generateUsers());
    const storedSubjects = localStorage.getItem('classSync_subjects');
    setSubjects(storedSubjects ? JSON.parse(storedSubjects) : initialSubjects);
    // ... load others similarly or just use mock defaults
    if (!storedUsers) setUsers(generateUsers());
    if (!storedSubjects) setSubjects(initialSubjects);
    setAnnouncements(initialAnnouncements);
    setTasks(initialTasks);
    setSchedule(initialSchedule);
    setVideos(initialVideos);
    setMaterials(initialMaterials);
    setTutorEvents(initialTutorEvents);
  };

  // --- Persistence Helper ---
  // We no longer use useEffect to persist to localStorage. 
  // Instead, we call Supabase in the action methods.

  // Dark Mode
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  const logActivity = async (action: string) => {
    if (!currentUser) return;
    const log: ActivityLog = {
      id: Date.now().toString(),
      userId: currentUser.id,
      action: `${currentUser.username} (${currentUser.role}): ${action}`,
      timestamp: new Date().toISOString()
    };
    setActivityLog(prev => [log, ...prev]);
    if (isSupabaseConfigured()) {
       await supabase.from('activity_logs').insert(log);
    }
  };

  const login = (u: string, p: string) => {
    const user = users.find(usr => usr.username === u && usr.password === p);
    if (user && user.isActive) {
      setCurrentUser(user);
      logActivity(`Logged in`);
      return true;
    }
    return false;
  };

  const loginWithGoogle = async (email: string, name: string, googleId: string) => {
    let user = users.find(u => u.username === email);

    if (!user) {
      user = {
        id: `g_${googleId}`,
        username: email,
        fullName: name,
        role: Role.STUDENT, 
        isActive: true,
        password: '', 
        seatIndex: null
      };
      setUsers(prev => [...prev, user!]);
      if (isSupabaseConfigured()) {
        await supabase.from('users').insert(user);
      }
    }

    if (user && user.isActive) {
      setCurrentUser(user);
      logActivity(`Logged in via Google`);
    }
  };

  const logout = () => {
    logActivity(`Logged out`);
    setCurrentUser(null);
  };

  // --- Actions with Supabase Integration ---

  const addAnnouncement = async (item: Announcement) => {
    setAnnouncements([item, ...announcements]);
    if (isSupabaseConfigured()) await supabase.from('announcements').insert(item);
    logActivity(`Added announcement: ${item.title}`);
  };

  const addTask = async (item: Task) => {
    setTasks([item, ...tasks]);
    if (isSupabaseConfigured()) await supabase.from('tasks').insert(item);
    logActivity(`Added task: ${item.title}`);
  };

  const toggleTaskCompletion = async (taskId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;
    const newStatus = !task.isCompleted;

    setTasks(tasks.map(t => t.id === taskId ? { ...t, isCompleted: newStatus } : t));

    if (isSupabaseConfigured()) {
      await supabase.from('tasks').update({ isCompleted: newStatus }).eq('id', taskId);
    }
  };

  const addSubject = async (subject: Subject) => {
    setSubjects([...subjects, subject]);
    if (isSupabaseConfigured()) await supabase.from('subjects').insert(subject);
    logActivity(`Added subject: ${subject.name}`);
  }

  const deleteSubject = async (id: string) => {
    setSubjects(subjects.filter(s => s.id !== id));
    if (isSupabaseConfigured()) await supabase.from('subjects').delete().eq('id', id);
    logActivity(`Deleted subject ID: ${id}`);
  }

  const addScheduleItem = async (item: ScheduleItem) => {
    setSchedule([...schedule, item]);
    if (isSupabaseConfigured()) await supabase.from('schedule').insert(item);
    logActivity(`Added schedule item for ${item.day}`);
  }

  const deleteScheduleItem = async (id: string) => {
    setSchedule(schedule.filter(s => s.id !== id));
    if (isSupabaseConfigured()) await supabase.from('schedule').delete().eq('id', id);
    logActivity(`Deleted schedule item ID: ${id}`);
  }

  const addVideo = async (video: VideoMaterial) => {
    setVideos([video, ...videos]);
    if (isSupabaseConfigured()) await supabase.from('videos').insert(video);
    logActivity(`Added video: ${video.title}`);
  }

  const deleteVideo = async (id: string) => {
    setVideos(videos.filter(v => v.id !== id));
    if (isSupabaseConfigured()) await supabase.from('videos').delete().eq('id', id);
    logActivity(`Deleted video ID: ${id}`);
  }

  const addMaterial = async (material: DocumentMaterial) => {
    setMaterials([material, ...materials]);
    if (isSupabaseConfigured()) await supabase.from('materials').insert(material);
    logActivity(`Added material: ${material.title}`);
  }

  const deleteMaterial = async (id: string) => {
    setMaterials(materials.filter(m => m.id !== id));
    if (isSupabaseConfigured()) await supabase.from('materials').delete().eq('id', id);
    logActivity(`Deleted material ID: ${id}`);
  }

  const addTutorEvent = async (event: TutorEvent) => {
    setTutorEvents([event, ...tutorEvents]);
    if (isSupabaseConfigured()) await supabase.from('tutor_events').insert(event);
    logActivity(`Added tutor event: ${event.title}`);
  };

  const editTutorEvent = async (id: string, updates: Partial<TutorEvent>) => {
    setTutorEvents(prev => prev.map(ev => ev.id === id ? { ...ev, ...updates } : ev));
    if (isSupabaseConfigured()) await supabase.from('tutor_events').update(updates).eq('id', id);
    logActivity(`Edited tutor event ID: ${id}`);
  };

  const deleteTutorEvent = async (id: string) => {
    setTutorEvents(tutorEvents.filter(e => e.id !== id));
    if (isSupabaseConfigured()) await supabase.from('tutor_events').delete().eq('id', id);
    logActivity(`Deleted tutor event ID: ${id}`);
  };

  const joinTutorEvent = async (eventId: string) => {
    if (!currentUser) return;
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    // Check if already in participants or waiting list
    if (event.participants.includes(currentUser.id) || (event.waitingList && event.waitingList.includes(currentUser.id))) {
      return;
    }

    if (event.participants.length < event.maxParticipants) {
      // Join as participant
      const newParticipants = [...event.participants, currentUser.id];
      setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, participants: newParticipants } : ev));

      if (isSupabaseConfigured()) {
        await supabase.from('tutor_events').update({ participants: newParticipants }).eq('id', eventId);
      }
      logActivity(`Joined tutor event ID: ${eventId}`);
    } else {
      // Join waiting list
      const currentWaitingList = event.waitingList || [];
      const newWaitingList = [...currentWaitingList, currentUser.id];
      setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, waitingList: newWaitingList } : ev));

      if (isSupabaseConfigured()) {
        await supabase.from('tutor_events').update({ waitingList: newWaitingList }).eq('id', eventId);
      }
      logActivity(`Joined waiting list for event ID: ${eventId}`);
    }
  };

  const leaveTutorEvent = async (eventId: string) => {
    if (!currentUser) return;
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    const isParticipant = event.participants.includes(currentUser.id);
    const isWaitlisted = event.waitingList && event.waitingList.includes(currentUser.id);

    if (isParticipant) {
        const newParticipants = event.participants.filter(id => id !== currentUser.id);
        setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, participants: newParticipants } : ev));
        if (isSupabaseConfigured()) {
            await supabase.from('tutor_events').update({ participants: newParticipants }).eq('id', eventId);
        }
        logActivity(`Left tutor event ID: ${eventId}`);
    } else if (isWaitlisted) {
        const newWaitingList = (event.waitingList || []).filter(id => id !== currentUser.id);
        setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, waitingList: newWaitingList } : ev));
        if (isSupabaseConfigured()) {
            await supabase.from('tutor_events').update({ waitingList: newWaitingList }).eq('id', eventId);
        }
        logActivity(`Left waiting list for event ID: ${eventId}`);
    }
  };

  const promoteFromWaitingList = async (eventId: string, userId: string) => {
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    // Remove from waiting list
    const newWaitingList = (event.waitingList || []).filter(id => id !== userId);

    // Add to participants if not already there
    let newParticipants = event.participants;
    if (!event.participants.includes(userId)) {
       newParticipants = [...event.participants, userId];
    }

    setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { 
        ...ev, 
        waitingList: newWaitingList,
        participants: newParticipants
    } : ev));

    if (isSupabaseConfigured()) {
       await supabase.from('tutor_events').update({ 
           waitingList: newWaitingList,
           participants: newParticipants
       }).eq('id', eventId);
    }
    logActivity(`Promoted user ${userId} from waiting list in event ${eventId}`);
  };

  const updateUserRole = async (userId: string, role: Role) => {
    setUsers(users.map(u => u.id === userId ? { ...u, role } : u));
    if (isSupabaseConfigured()) await supabase.from('users').update({ role }).eq('id', userId);
    logActivity(`Updated user ${userId} to role ${role}`);
  };

  const updateUserStatus = async (userId: string, isActive: boolean) => {
    setUsers(users.map(u => u.id === userId ? { ...u, isActive } : u));
    if (isSupabaseConfigured()) await supabase.from('users').update({ isActive }).eq('id', userId);
    logActivity(`Updated user ${userId} active status to ${isActive}`);
  };

  const updateUserProfile = async (userId: string, data: { fullName?: string, password?: string }) => {
    const updates: any = {};
    if (data.fullName) updates.fullName = data.fullName;
    if (data.password) updates.password = data.password;

    setUsers(users.map(u => {
      if (u.id === userId) {
        return { ...u, ...updates };
      }
      return u;
    }));

    if (currentUser && currentUser.id === userId) {
      setCurrentUser(prev => prev ? { ...prev, ...updates } : null);
    }

    if (isSupabaseConfigured()) await supabase.from('users').update(updates).eq('id', userId);
    logActivity(`User ${userId} updated their profile`);
  };

  const updateSeat = async (userId: string, seatIndex: number | null) => {
    setUsers(prev => prev.map(u => {
      if (u.id === userId) return { ...u, seatIndex };
      if (seatIndex !== null && u.seatIndex === seatIndex) return { ...u, seatIndex: null };
      return u;
    }));

    // In DB we need to handle the swap carefully, but for now just update the target user
    // Ideally we update the old seat holder to null too if needed
    if (isSupabaseConfigured()) {
       if (seatIndex !== null) {
           // Clear anyone else on this seat
           await supabase.from('users').update({ seatIndex: null }).eq('seatIndex', seatIndex);
       }
       await supabase.from('users').update({ seatIndex }).eq('id', userId);
    }
    logActivity(`Updated seat for user ${userId}`);
  };

  const resetSeats = async () => {
     setUsers(prev => prev.map(u => ({ ...u, seatIndex: null })));
     if (isSupabaseConfigured()) await supabase.from('users').update({ seatIndex: null }).neq('id', '0'); // update all
     logActivity('Reset all seats');
  };

  const randomizeSeats = async () => {
    const students = users.filter(u => u.role === Role.STUDENT);
    const studentIds = students.map(u => u.id);
    const shuffled = [...studentIds].sort(() => Math.random() - 0.5);

    const updates = students.map(u => {
      const idx = shuffled.indexOf(u.id);
      return { id: u.id, seatIndex: idx < 35 ? idx : null };
    });

    // Optimistic update
    setUsers(prev => prev.map(u => {
      if (u.role === Role.STUDENT) {
        const up = updates.find(x => x.id === u.id);
        return { ...u, seatIndex: up ? up.seatIndex : null };
      }
      return u;
    }));

    if (isSupabaseConfigured()) {
        // Batch update is hard in REST without RPC, loop for now (not efficient but works for 35 users)
        for (const up of updates) {
            await supabase.from('users').update({ seatIndex: up.seatIndex }).eq('id', up.id);
        }
    }
    logActivity('Randomized seats');
  };

  return (
    <StoreContext.Provider value={{
      currentUser, users, subjects, announcements, tasks, schedule, videos, materials, tutorEvents, activityLog, isDarkMode, isLoading,
      toggleDarkMode, login, loginWithGoogle, logout, 
      addAnnouncement, addTask, toggleTaskCompletion,
      addSubject, deleteSubject, addScheduleItem, deleteScheduleItem,
      addVideo, deleteVideo,
      addMaterial, deleteMaterial,
      addTutorEvent, editTutorEvent, deleteTutorEvent, joinTutorEvent, leaveTutorEvent, promoteFromWaitingList,
      updateUserRole, updateUserStatus, updateUserProfile,
      updateSeat, resetSeats, randomizeSeats
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error("useStore must be used within StoreProvider");
  return context;
};

import React, { useState } from 'react';
import { useStore } from '../context/Store';
import { Role, TutorEvent } from '../types';
import { GraduationCap, Plus, Calendar, User, Clock, Trash2, LogIn, LogOut, Users, Edit, UserPlus, ClipboardList } from 'lucide-react';

export const TutorEvents = () => {
  const { tutorEvents, users, currentUser, addTutorEvent, editTutorEvent, deleteTutorEvent, joinTutorEvent, leaveTutorEvent, promoteFromWaitingList } = useStore();

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isEditMode, setIsEditMode] = useState(false);
  const [editingEventId, setEditingEventId] = useState<string | null>(null);

  const [eventForm, setEventForm] = useState({ title: '', description: '', date: '', time: '', maxParticipants: 5 });

  const canCreate = [Role.MURID_BIBILUNG, Role.ADMIN].includes(currentUser?.role as Role);
  const canJoin = currentUser?.role === Role.STUDENT || currentUser?.role === Role.MURID_BIBILUNG;

  const openCreateModal = () => {
    setIsEditMode(false);
    setEventForm({ title: '', description: '', date: '', time: '', maxParticipants: 5 });
    setIsModalOpen(true);
  };

  const openEditModal = (event: TutorEvent) => {
    setIsEditMode(true);
    setEditingEventId(event.id);
    const dateObj = new Date(event.date);
    // Format date YYYY-MM-DD
    const dateStr = dateObj.toISOString().split('T')[0];
    // Format time HH:MM
    const timeStr = dateObj.toTimeString().substring(0, 5);

    setEventForm({
        title: event.title,
        description: event.description,
        date: dateStr,
        time: timeStr,
        maxParticipants: event.maxParticipants
    });
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    // Combine date and time
    const dateTime = new Date(`${eventForm.date}T${eventForm.time}`);

    if (isEditMode && editingEventId) {
        editTutorEvent(editingEventId, {
            title: eventForm.title,
            description: eventForm.description,
            date: dateTime.toISOString(),
            maxParticipants: Number(eventForm.maxParticipants)
        });
    } else {
        addTutorEvent({
            id: Date.now().toString(),
            title: eventForm.title,
            description: eventForm.description,
            date: dateTime.toISOString(),
            tutorId: currentUser.id,
            tutorName: currentUser.fullName,
            maxParticipants: Number(eventForm.maxParticipants),
            participants: [],
            waitingList: []
        });
    }

    setIsModalOpen(false);
  };

  const getCapacityColor = (current: number, max: number) => {
    const percentage = current / max;
    if (percentage >= 1) return 'bg-red-500';
    if (percentage >= 0.8) return 'bg-yellow-500';
    return 'bg-green-500';
  };

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-6">
        <div>
           <h1 className="text-3xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <GraduationCap /> Tutor Events
          </h1>
          <p className="text-gray-500 dark:text-gray-400 mt-1">
             Exclusive sessions hosted by our Murid Bibilung. First come, first served!
          </p>
        </div>

        {canCreate && (
          <button 
            onClick={openCreateModal}
            className="bg-primary text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-600 transition"
          >
            <Plus size={18} /> Create Event
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {tutorEvents.map(event => {
          const isFull = event.participants.length >= event.maxParticipants;
          const isJoined = currentUser ? event.participants.includes(currentUser.id) : false;
          const isWaitlisted = currentUser ? (event.waitingList || []).includes(currentUser.id) : false;

          const isCreator = currentUser?.id === event.tutorId;
          const canManage = isCreator || currentUser?.role === Role.ADMIN || currentUser?.role === Role.KURIKULUM;
          const eventDate = new Date(event.date);

          // Get participant objects to display names
          const joinedUsers = users.filter(u => event.participants.includes(u.id));
          const waitingUsers = users.filter(u => (event.waitingList || []).includes(u.id));

          return (
            <div key={event.id} className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col overflow-hidden transition hover:shadow-md">
               <div className="p-6 flex-1 flex flex-col">
                  <div className="flex justify-between items-start mb-3">
                     <span className="bg-purple-100 text-purple-800 text-xs font-bold px-2 py-1 rounded dark:bg-purple-900/30 dark:text-purple-300 uppercase tracking-wide">
                        Bibilung Class
                     </span>
                     {canManage && (
                       <div className="flex gap-1">
                         <button onClick={() => openEditModal(event)} className="text-gray-400 hover:text-blue-500 transition p-1">
                            <Edit size={16} />
                         </button>
                         <button onClick={() => deleteTutorEvent(event.id)} className="text-gray-400 hover:text-red-500 transition p-1">
                           <Trash2 size={16} />
                         </button>
                       </div>
                     )}
                  </div>

                  <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-2">{event.title}</h3>
                  <p className="text-gray-600 dark:text-gray-300 text-sm mb-4 line-clamp-2">{event.description}</p>

                  <div className="space-y-2 text-sm text-gray-500 dark:text-gray-400 mb-6">
                     <div className="flex items-center gap-2">
                        <User size={16} className="text-primary" />
                        <span>Tutor: <span className="font-semibold text-gray-700 dark:text-gray-200">{event.tutorName}</span></span>
                     </div>
                     <div className="flex items-center gap-2">
                        <Calendar size={16} className="text-primary" />
                        <span>{eventDate.toLocaleDateString()}</span>
                     </div>
                     <div className="flex items-center gap-2">
                        <Clock size={16} className="text-primary" />
                        <span>{eventDate.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                     </div>
                  </div>

                  {/* Participant List */}
                  <div className="mt-auto pt-4 border-t border-gray-100 dark:border-gray-700">
                     <div className="flex items-center gap-2 mb-2 text-xs font-semibold text-gray-500 dark:text-gray-400">
                        <Users size={14} /> Registered Students ({joinedUsers.length})
                     </div>
                     <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto custom-scrollbar">
                        {joinedUsers.length === 0 ? (
                           <span className="text-xs text-gray-400 italic">No participants yet.</span>
                        ) : (
                           joinedUsers.map(u => (
                             <div key={u.id} className="flex items-center gap-1.5 bg-gray-100 dark:bg-gray-700/50 px-2 py-1 rounded-full border border-gray-200 dark:border-gray-600" title={u.fullName}>
                                <div className="w-5 h-5 rounded-full bg-primary/20 text-primary flex items-center justify-center text-[10px] font-bold">
                                   {u.username.substring(0,2).toUpperCase()}
                                </div>
                                <span className="text-xs text-gray-700 dark:text-gray-300 max-w-[80px] truncate">{u.fullName.split(' ')[0]}</span> 
                             </div>
                           ))
                        )}
                     </div>
                  </div>

                  {/* Waiting List - Only Visible to Admin/Kurikulum/Owner */}
                  {canManage && waitingUsers.length > 0 && (
                      <div className="mt-4 pt-4 border-t border-dashed border-gray-200 dark:border-gray-600">
                          <div className="flex items-center gap-2 mb-2 text-xs font-semibold text-yellow-600 dark:text-yellow-500">
                             <ClipboardList size={14} /> Waiting List ({waitingUsers.length})
                          </div>
                          <div className="space-y-2">
                              {waitingUsers.map(u => (
                                  <div key={u.id} className="flex justify-between items-center text-xs bg-yellow-50 dark:bg-yellow-900/10 p-2 rounded">
                                      <span className="text-gray-700 dark:text-gray-300">{u.fullName}</span>
                                      <button 
                                        onClick={() => promoteFromWaitingList(event.id, u.id)}
                                        className="flex items-center gap-1 bg-white dark:bg-gray-800 border border-green-200 text-green-600 px-2 py-1 rounded shadow-sm hover:bg-green-50 transition"
                                        title="Assign to class"
                                      >
                                          <UserPlus size={12} /> Assign
                                      </button>
                                  </div>
                              ))}
                          </div>
                      </div>
                  )}
               </div>

               <div className="bg-gray-50 dark:bg-gray-750 p-4 border-t dark:border-gray-700">
                  <div className="flex justify-between items-center mb-3 text-sm">
                     <span className="font-medium text-gray-600 dark:text-gray-300">Quota</span>
                     <span className={`${isFull ? 'text-red-500' : 'text-green-600'} font-bold`}>
                        {event.participants.length} / {event.maxParticipants}
                     </span>
                  </div>
                  <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2 mb-4 overflow-hidden">
                     <div 
                        className={`h-2 rounded-full transition-all duration-500 ${getCapacityColor(event.participants.length, event.maxParticipants)}`} 
                        style={{ width: `${(event.participants.length / event.maxParticipants) * 100}%` }}
                     ></div>
                  </div>

                  {isJoined ? (
                     <button 
                        onClick={() => leaveTutorEvent(event.id)}
                        className="w-full py-2 rounded-lg border border-red-200 text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 dark:border-red-900 dark:text-red-400 flex items-center justify-center gap-2 transition"
                     >
                        <LogOut size={18} /> Leave Class
                     </button>
                  ) : isWaitlisted ? (
                    <button 
                        onClick={() => leaveTutorEvent(event.id)}
                        className="w-full py-2 rounded-lg border border-yellow-200 text-yellow-600 hover:bg-yellow-50 dark:hover:bg-yellow-900/20 dark:border-yellow-900 dark:text-yellow-400 flex items-center justify-center gap-2 transition"
                     >
                        <LogOut size={18} /> Leave Waitlist
                     </button>
                  ) : (
                     <button 
                        onClick={() => joinTutorEvent(event.id)}
                        disabled={!canJoin}
                        className={`w-full py-2 rounded-lg text-white flex items-center justify-center gap-2 transition font-medium
                           ${!canJoin 
                              ? 'bg-gray-300 dark:bg-gray-700 cursor-not-allowed text-gray-500' 
                              : isFull 
                                ? 'bg-yellow-500 hover:bg-yellow-600 text-white' 
                                : 'bg-primary hover:bg-blue-600 shadow-sm hover:shadow'
                           }
                        `}
                     >
                        {!canJoin ? 'Students Only' : isFull ? 'Join Waitlist' : <><LogIn size={18} /> Join Class</>}
                     </button>
                  )}
               </div>
            </div>
          );
        })}
      </div>

      {tutorEvents.length === 0 && (
         <div className="text-center py-20 text-gray-400 bg-gray-50 dark:bg-gray-800/50 rounded-xl border border-dashed border-gray-200 dark:border-gray-700 mt-8">
            <GraduationCap size={48} className="mx-auto mb-4 opacity-50" />
            <p className="text-lg font-medium">No active tutor events yet.</p>
            {canCreate && <p className="text-sm">Be the first Murid Bibilung to create one!</p>}
         </div>
      )}

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 animate-fade-in">
          <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl w-full max-w-md shadow-2xl transform scale-100 transition-all">
            <h3 className="text-xl font-bold mb-4 dark:text-white flex items-center gap-2">
               {isEditMode ? <Edit className="bg-primary text-white rounded-full p-1" size={24} /> : <Plus className="bg-primary text-white rounded-full p-1" size={24} />}
               {isEditMode ? 'Edit Tutor Event' : 'Create Tutor Event'}
            </h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                 <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Topic / Title</label>
                 <input 
                  className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:ring-2 focus:ring-primary outline-none"
                  placeholder="e.g. Advanced CSS Grid"
                  required
                  value={eventForm.title}
                  onChange={e => setEventForm({...eventForm, title: e.target.value})}
                />
              </div>

              <div>
                 <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Description</label>
                 <textarea 
                  className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:ring-2 focus:ring-primary outline-none"
                  placeholder="What will be discussed?"
                  rows={3}
                  required
                  value={eventForm.description}
                  onChange={e => setEventForm({...eventForm, description: e.target.value})}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Date</label>
                    <input 
                     type="date"
                     className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:ring-2 focus:ring-primary outline-none"
                     required
                     value={eventForm.date}
                     onChange={e => setEventForm({...eventForm, date: e.target.value})}
                   />
                 </div>
                 <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Time</label>
                    <input 
                     type="time"
                     className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:ring-2 focus:ring-primary outline-none"
                     required
                     value={eventForm.time}
                     onChange={e => setEventForm({...eventForm, time: e.target.value})}
                   />
                 </div>
              </div>

              <div>
                 <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Max Participants</label>
                 <input 
                  type="number"
                  min="1"
                  max="50"
                  className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:ring-2 focus:ring-primary outline-none"
                  required
                  value={eventForm.maxParticipants}
                  onChange={e => setEventForm({...eventForm, maxParticipants: Number(e.target.value)})}
                />
                <p className="text-xs text-gray-500 mt-1">First come, first served basis.</p>
              </div>

              <div className="flex justify-end gap-2 pt-2">
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg transition">Cancel</button>
                <button type="submit" className="px-6 py-2 bg-primary text-white rounded-lg shadow hover:bg-blue-600 transition">
                    {isEditMode ? 'Update Event' : 'Create Event'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, Role, Announcement, Task, ScheduleItem, VideoMaterial, ActivityLog, Subject, DocumentMaterial, TutorEvent } from '../types';
import { generateUsers, initialAnnouncements, initialTasks, initialSchedule, initialVideos, initialSubjects, initialMaterials, initialTutorEvents } from '../services/mockData';
import { supabase, isSupabaseConfigured } from '../services/supabaseClient';

interface StoreContextType {
  currentUser: User | null;
  users: User[];
  subjects: Subject[];
  announcements: Announcement[];
  tasks: Task[];
  schedule: ScheduleItem[];
  videos: VideoMaterial[];
  materials: DocumentMaterial[];
  tutorEvents: TutorEvent[];
  activityLog: ActivityLog[];
  isDarkMode: boolean;
  isLoading: boolean;

  toggleDarkMode: () => void;
  login: (username: string, password: string) => boolean;
  loginWithGoogle: (email: string, name: string, googleId: string) => void;
  logout: () => void;

  // Data manipulation
  addAnnouncement: (announcement: Announcement) => void;
  addTask: (task: Task) => void;
  toggleTaskCompletion: (taskId: string) => void;

  addSubject: (subject: Subject) => void;
  deleteSubject: (id: string) => void;

  addScheduleItem: (item: ScheduleItem) => void;
  deleteScheduleItem: (id: string) => void;

  addVideo: (video: VideoMaterial) => void;
  deleteVideo: (id: string) => void;

  addMaterial: (material: DocumentMaterial) => void;
  deleteMaterial: (id: string) => void;

  addTutorEvent: (event: TutorEvent) => void;
  editTutorEvent: (id: string, updates: Partial<TutorEvent>) => void;
  deleteTutorEvent: (id: string) => void;
  joinTutorEvent: (eventId: string) => void;
  leaveTutorEvent: (eventId: string) => void;
  promoteFromWaitingList: (eventId: string, userId: string) => void;
  assignUserToEvent: (eventId: string, userId: string) => void;
  kickFromEvent: (eventId: string, userId: string) => void;

  updateUserRole: (userId: string, role: Role) => void;
  updateUserStatus: (userId: string, isActive: boolean) => void;
  updateUserProfile: (userId: string, data: { fullName?: string, password?: string }) => void;

  updateSeat: (userId: string, seatIndex: number | null) => void;
  resetSeats: () => void;
  randomizeSeats: () => void;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider = ({ children }: { children?: ReactNode }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Data States
  const [users, setUsers] = useState<User[]>([]);
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [schedule, setSchedule] = useState<ScheduleItem[]>([]);
  const [videos, setVideos] = useState<VideoMaterial[]>([]);
  const [materials, setMaterials] = useState<DocumentMaterial[]>([]);
  const [tutorEvents, setTutorEvents] = useState<TutorEvent[]>([]);
  const [activityLog, setActivityLog] = useState<ActivityLog[]>([]);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  // --- Initial Data Fetching ---
  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);

      // 1. Check if Supabase is configured
      if (!isSupabaseConfigured()) {
        console.warn("Supabase credentials missing. Falling back to local/mock data.");
        loadLocalData();
        setIsLoading(false);
        return;
      }

      try {
        // 2. Fetch Users
        const { data: dbUsers, error: userError } = await supabase.from('users').select('*');
        if (dbUsers && dbUsers.length > 0) {
          setUsers(dbUsers);
        } else {
          // Seed initial users if DB is empty
          const seedUsers = generateUsers();
          await supabase.from('users').insert(seedUsers);
          setUsers(seedUsers);
        }

        // 3. Fetch Subjects
        const { data: dbSubjects } = await supabase.from('subjects').select('*');
        setSubjects(dbSubjects?.length ? dbSubjects : []);

        // 4. Fetch Announcements
        const { data: dbAnnounce } = await supabase.from('announcements').select('*').order('date', { ascending: false });
        setAnnouncements(dbAnnounce?.length ? dbAnnounce : []);

        // 5. Fetch Tasks
        const { data: dbTasks } = await supabase.from('tasks').select('*').order('deadline', { ascending: true });
        setTasks(dbTasks?.length ? dbTasks : []);

        // 6. Fetch Schedule
        const { data: dbSchedule } = await supabase.from('schedule').select('*');
        setSchedule(dbSchedule?.length ? dbSchedule : []);

        // 7. Fetch Videos
        const { data: dbVideos } = await supabase.from('videos').select('*');
        setVideos(dbVideos?.length ? dbVideos : []);

        // 8. Fetch Materials
        const { data: dbMaterials } = await supabase.from('materials').select('*');
        setMaterials(dbMaterials?.length ? dbMaterials : []);

        // 9. Fetch Tutor Events
        const { data: dbEvents } = await supabase.from('tutor_events').select('*');
        setTutorEvents(dbEvents?.length ? dbEvents : []);

        // 10. Fetch Logs
        const { data: dbLogs } = await supabase.from('activity_logs').select('*').order('timestamp', { ascending: false }).limit(50);
        setActivityLog(dbLogs?.length ? dbLogs : []);

      } catch (error) {
        console.error("Error fetching data from Supabase:", error);
        loadLocalData(); // Fallback on error
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  const loadLocalData = () => {
    // Fallback logic from previous version
    const storedUsers = localStorage.getItem('classSync_users');
    setUsers(storedUsers ? JSON.parse(storedUsers) : generateUsers());
    const storedSubjects = localStorage.getItem('classSync_subjects');
    setSubjects(storedSubjects ? JSON.parse(storedSubjects) : initialSubjects);
    // ... load others similarly or just use mock defaults
    if (!storedUsers) setUsers(generateUsers());
    if (!storedSubjects) setSubjects(initialSubjects);
    setAnnouncements(initialAnnouncements);
    setTasks(initialTasks);
    setSchedule(initialSchedule);
    setVideos(initialVideos);
    setMaterials(initialMaterials);
    setTutorEvents(initialTutorEvents);
  };

  // --- Persistence Helper ---
  // We no longer use useEffect to persist to localStorage. 
  // Instead, we call Supabase in the action methods.

  // Dark Mode
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  const logActivity = async (action: string) => {
    if (!currentUser) return;
    const log: ActivityLog = {
      id: Date.now().toString(),
      userId: currentUser.id,
      action: `${currentUser.username} (${currentUser.role}): ${action}`,
      timestamp: new Date().toISOString()
    };
    setActivityLog(prev => [log, ...prev]);
    if (isSupabaseConfigured()) {
       await supabase.from('activity_logs').insert(log);
    }
  };

  const login = (u: string, p: string) => {
    const user = users.find(usr => usr.username === u && usr.password === p);
    if (user && user.isActive) {
      setCurrentUser(user);
      logActivity(`Logged in`);
      return true;
    }
    return false;
  };

  const loginWithGoogle = async (email: string, name: string, googleId: string) => {
    let user = users.find(u => u.username === email);

    if (!user) {
      user = {
        id: `g_${googleId}`,
        username: email,
        fullName: name,
        role: Role.STUDENT, 
        isActive: true,
        password: '', 
        seatIndex: null
      };
      setUsers(prev => [...prev, user!]);
      if (isSupabaseConfigured()) {
        await supabase.from('users').insert(user);
      }
    }

    if (user && user.isActive) {
      setCurrentUser(user);
      logActivity(`Logged in via Google`);
    }
  };

  const logout = () => {
    logActivity(`Logged out`);
    setCurrentUser(null);
  };

  // --- Actions with Supabase Integration ---

  const addAnnouncement = async (item: Announcement) => {
    setAnnouncements([item, ...announcements]);
    if (isSupabaseConfigured()) await supabase.from('announcements').insert(item);
    logActivity(`Added announcement: ${item.title}`);
  };

  const addTask = async (item: Task) => {
    setTasks([item, ...tasks]);
    if (isSupabaseConfigured()) await supabase.from('tasks').insert(item);
    logActivity(`Added task: ${item.title}`);
  };

  const toggleTaskCompletion = async (taskId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;
    const newStatus = !task.isCompleted;

    setTasks(tasks.map(t => t.id === taskId ? { ...t, isCompleted: newStatus } : t));

    if (isSupabaseConfigured()) {
      await supabase.from('tasks').update({ isCompleted: newStatus }).eq('id', taskId);
    }
  };

  const addSubject = async (subject: Subject) => {
    setSubjects([...subjects, subject]);
    if (isSupabaseConfigured()) await supabase.from('subjects').insert(subject);
    logActivity(`Added subject: ${subject.name}`);
  }

  const deleteSubject = async (id: string) => {
    setSubjects(subjects.filter(s => s.id !== id));
    if (isSupabaseConfigured()) await supabase.from('subjects').delete().eq('id', id);
    logActivity(`Deleted subject ID: ${id}`);
  }

  const addScheduleItem = async (item: ScheduleItem) => {
    setSchedule([...schedule, item]);
    if (isSupabaseConfigured()) await supabase.from('schedule').insert(item);
    logActivity(`Added schedule item for ${item.day}`);
  }

  const deleteScheduleItem = async (id: string) => {
    setSchedule(schedule.filter(s => s.id !== id));
    if (isSupabaseConfigured()) await supabase.from('schedule').delete().eq('id', id);
    logActivity(`Deleted schedule item ID: ${id}`);
  }

  const addVideo = async (video: VideoMaterial) => {
    setVideos([video, ...videos]);
    if (isSupabaseConfigured()) await supabase.from('videos').insert(video);
    logActivity(`Added video: ${video.title}`);
  }

  const deleteVideo = async (id: string) => {
    setVideos(videos.filter(v => v.id !== id));
    if (isSupabaseConfigured()) await supabase.from('videos').delete().eq('id', id);
    logActivity(`Deleted video ID: ${id}`);
  }

  const addMaterial = async (material: DocumentMaterial) => {
    setMaterials([material, ...materials]);
    if (isSupabaseConfigured()) await supabase.from('materials').insert(material);
    logActivity(`Added material: ${material.title}`);
  }

  const deleteMaterial = async (id: string) => {
    setMaterials(materials.filter(m => m.id !== id));
    if (isSupabaseConfigured()) await supabase.from('materials').delete().eq('id', id);
    logActivity(`Deleted material ID: ${id}`);
  }

  const addTutorEvent = async (event: TutorEvent) => {
    setTutorEvents([event, ...tutorEvents]);
    if (isSupabaseConfigured()) await supabase.from('tutor_events').insert(event);
    logActivity(`Added tutor event: ${event.title}`);
  };

  const editTutorEvent = async (id: string, updates: Partial<TutorEvent>) => {
    setTutorEvents(prev => prev.map(ev => ev.id === id ? { ...ev, ...updates } : ev));
    if (isSupabaseConfigured()) await supabase.from('tutor_events').update(updates).eq('id', id);
    logActivity(`Edited tutor event ID: ${id}`);
  };

  const deleteTutorEvent = async (id: string) => {
    setTutorEvents(tutorEvents.filter(e => e.id !== id));
    if (isSupabaseConfigured()) await supabase.from('tutor_events').delete().eq('id', id);
    logActivity(`Deleted tutor event ID: ${id}`);
  };

  const joinTutorEvent = async (eventId: string) => {
    if (!currentUser) return;
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    // Check if already in participants or waiting list
    if (event.participants.includes(currentUser.id) || (event.waitingList && event.waitingList.includes(currentUser.id))) {
      return;
    }

    if (event.participants.length < event.maxParticipants) {
      // Join as participant
      const newParticipants = [...event.participants, currentUser.id];
      setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, participants: newParticipants } : ev));

      if (isSupabaseConfigured()) {
        await supabase.from('tutor_events').update({ participants: newParticipants }).eq('id', eventId);
      }
      logActivity(`Joined tutor event ID: ${eventId}`);
    } else {
      // Join waiting list
      const currentWaitingList = event.waitingList || [];
      const newWaitingList = [...currentWaitingList, currentUser.id];
      setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, waitingList: newWaitingList } : ev));

      if (isSupabaseConfigured()) {
        await supabase.from('tutor_events').update({ waitingList: newWaitingList }).eq('id', eventId);
      }
      logActivity(`Joined waiting list for event ID: ${eventId}`);
    }
  };

  const leaveTutorEvent = async (eventId: string) => {
    if (!currentUser) return;
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    const isParticipant = event.participants.includes(currentUser.id);
    const isWaitlisted = event.waitingList && event.waitingList.includes(currentUser.id);

    if (isParticipant) {
        const newParticipants = event.participants.filter(id => id !== currentUser.id);
        setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, participants: newParticipants } : ev));
        if (isSupabaseConfigured()) {
            await supabase.from('tutor_events').update({ participants: newParticipants }).eq('id', eventId);
        }
        logActivity(`Left tutor event ID: ${eventId}`);
    } else if (isWaitlisted) {
        const newWaitingList = (event.waitingList || []).filter(id => id !== currentUser.id);
        setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, waitingList: newWaitingList } : ev));
        if (isSupabaseConfigured()) {
            await supabase.from('tutor_events').update({ waitingList: newWaitingList }).eq('id', eventId);
        }
        logActivity(`Left waiting list for event ID: ${eventId}`);
    }
  };

  const promoteFromWaitingList = async (eventId: string, userId: string) => {
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    // Remove from waiting list
    const newWaitingList = (event.waitingList || []).filter(id => id !== userId);

    // Add to participants if not already there
    let newParticipants = event.participants;
    if (!event.participants.includes(userId)) {
       newParticipants = [...event.participants, userId];
    }

    setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { 
        ...ev, 
        waitingList: newWaitingList,
        participants: newParticipants
    } : ev));

    if (isSupabaseConfigured()) {
       await supabase.from('tutor_events').update({ 
           waitingList: newWaitingList,
           participants: newParticipants
       }).eq('id', eventId);
    }
    logActivity(`Promoted user ${userId} from waiting list in event ${eventId}`);
  };

  const assignUserToEvent = async (eventId: string, userId: string) => {
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    if (event.participants.includes(userId)) return;

    const newWaitingList = (event.waitingList || []).filter(id => id !== userId);
    const newParticipants = [...event.participants, userId];

    setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { 
        ...ev, 
        waitingList: newWaitingList,
        participants: newParticipants
    } : ev));

    if (isSupabaseConfigured()) {
       await supabase.from('tutor_events').update({ 
           waitingList: newWaitingList,
           participants: newParticipants
       }).eq('id', eventId);
    }
    logActivity(`Assigned user ${userId} to event ${eventId}`);
  };

  const kickFromEvent = async (eventId: string, userId: string) => {
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    const newParticipants = event.participants.filter(id => id !== userId);
    setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, participants: newParticipants } : ev));

    if (isSupabaseConfigured()) {
        await supabase.from('tutor_events').update({ participants: newParticipants }).eq('id', eventId);
    }
    logActivity(`Removed user ${userId} from event ${eventId}`);
  };

  const updateUserRole = async (userId: string, role: Role) => {
    setUsers(users.map(u => u.id === userId ? { ...u, role } : u));
    if (isSupabaseConfigured()) await supabase.from('users').update({ role }).eq('id', userId);
    logActivity(`Updated user ${userId} to role ${role}`);
  };

  const updateUserStatus = async (userId: string, isActive: boolean) => {
    setUsers(users.map(u => u.id === userId ? { ...u, isActive } : u));
    if (isSupabaseConfigured()) await supabase.from('users').update({ isActive }).eq('id', userId);
    logActivity(`Updated user ${userId} active status to ${isActive}`);
  };

  const updateUserProfile = async (userId: string, data: { fullName?: string, password?: string }) => {
    const updates: any = {};
    if (data.fullName) updates.fullName = data.fullName;
    if (data.password) updates.password = data.password;

    setUsers(users.map(u => {
      if (u.id === userId) {
        return { ...u, ...updates };
      }
      return u;
    }));

    if (currentUser && currentUser.id === userId) {
      setCurrentUser(prev => prev ? { ...prev, ...updates } : null);
    }

    if (isSupabaseConfigured()) await supabase.from('users').update(updates).eq('id', userId);
    logActivity(`User ${userId} updated their profile`);
  };

  const updateSeat = async (userId: string, seatIndex: number | null) => {
    setUsers(prev => prev.map(u => {
      if (u.id === userId) return { ...u, seatIndex };
      if (seatIndex !== null && u.seatIndex === seatIndex) return { ...u, seatIndex: null };
      return u;
    }));

    // In DB we need to handle the swap carefully, but for now just update the target user
    // Ideally we update the old seat holder to null too if needed
    if (isSupabaseConfigured()) {
       if (seatIndex !== null) {
           // Clear anyone else on this seat
           await supabase.from('users').update({ seatIndex: null }).eq('seatIndex', seatIndex);
       }
       await supabase.from('users').update({ seatIndex }).eq('id', userId);
    }
    logActivity(`Updated seat for user ${userId}`);
  };

  const resetSeats = async () => {
     setUsers(prev => prev.map(u => ({ ...u, seatIndex: null })));
     if (isSupabaseConfigured()) await supabase.from('users').update({ seatIndex: null }).neq('id', '0'); // update all
     logActivity('Reset all seats');
  };

  const randomizeSeats = async () => {
    const students = users.filter(u => u.role === Role.STUDENT);
    const studentIds = students.map(u => u.id);
    const shuffled = [...studentIds].sort(() => Math.random() - 0.5);

    const updates = students.map(u => {
      const idx = shuffled.indexOf(u.id);
      return { id: u.id, seatIndex: idx < 35 ? idx : null };
    });

    // Optimistic update
    setUsers(prev => prev.map(u => {
      if (u.role === Role.STUDENT) {
        const up = updates.find(x => x.id === u.id);
        return { ...u, seatIndex: up ? up.seatIndex : null };
      }
      return u;
    }));

    if (isSupabaseConfigured()) {
        // Batch update is hard in REST without RPC, loop for now (not efficient but works for 35 users)
        for (const up of updates) {
            await supabase.from('users').update({ seatIndex: up.seatIndex }).eq('id', up.id);
        }
    }
    logActivity('Randomized seats');
  };

  return (
    <StoreContext.Provider value={{
      currentUser, users, subjects, announcements, tasks, schedule, videos, materials, tutorEvents, activityLog, isDarkMode, isLoading,
      toggleDarkMode, login, loginWithGoogle, logout, 
      addAnnouncement, addTask, toggleTaskCompletion,
      addSubject, deleteSubject, addScheduleItem, deleteScheduleItem,
      addVideo, deleteVideo,
      addMaterial, deleteMaterial,
      addTutorEvent, editTutorEvent, deleteTutorEvent, joinTutorEvent, leaveTutorEvent, promoteFromWaitingList, assignUserToEvent, kickFromEvent,
      updateUserRole, updateUserStatus, updateUserProfile,
      updateSeat, resetSeats, randomizeSeats
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error("useStore must be used within StoreProvider");
  return context;
};

import React, { useState } from 'react';
import { useStore } from '../context/Store';
import { Role, TutorEvent } from '../types';
import { GraduationCap, Plus, Calendar, User, Clock, Trash2, LogIn, LogOut, Users, Edit, UserPlus, ClipboardList, Eye, X } from 'lucide-react';

export const TutorEvents = () => {
  const { 
    tutorEvents, users, currentUser, 
    addTutorEvent, editTutorEvent, deleteTutorEvent, 
    joinTutorEvent, leaveTutorEvent, promoteFromWaitingList,
    assignUserToEvent, kickFromEvent
  } = useStore();

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isEditMode, setIsEditMode] = useState(false);
  const [viewOnly, setViewOnly] = useState(false);
  const [editingEventId, setEditingEventId] = useState<string | null>(null);

  const [eventForm, setEventForm] = useState({ title: '', description: '', date: '', time: '', maxParticipants: 5 });
  const [studentToAssign, setStudentToAssign] = useState('');

  const canCreate = [Role.MURID_BIBILUNG, Role.ADMIN].includes(currentUser?.role as Role);
  const canJoin = currentUser?.role === Role.STUDENT || currentUser?.role === Role.MURID_BIBILUNG;

  const openCreateModal = () => {
    setIsEditMode(false);
    setViewOnly(false);
    setEventForm({ title: '', description: '', date: '', time: '', maxParticipants: 5 });
    setIsModalOpen(true);
  };

  const populateForm = (event: TutorEvent) => {
    setEditingEventId(event.id);
    const dateObj = new Date(event.date);
    const dateStr = dateObj.toISOString().split('T')[0];
    const timeStr = dateObj.toTimeString().substring(0, 5);
    setEventForm({
        title: event.title,
        description: event.description,
        date: dateStr,
        time: timeStr,
        maxParticipants: event.maxParticipants
    });
  }

  const openViewModal = (event: TutorEvent) => {
    setIsEditMode(false);
    setViewOnly(true);
    populateForm(event);
    setIsModalOpen(true);
  }

  const openEditModal = (event: TutorEvent) => {
    setIsEditMode(true);
    setViewOnly(false);
    populateForm(event);
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    // Combine date and time
    const dateTime = new Date(`${eventForm.date}T${eventForm.time}`);

    if (isEditMode && editingEventId) {
        editTutorEvent(editingEventId, {
            title: eventForm.title,
            description: eventForm.description,
            date: dateTime.toISOString(),
            maxParticipants: Number(eventForm.maxParticipants)
        });
    } else {
        addTutorEvent({
            id: Date.now().toString(),
            title: eventForm.title,
            description: eventForm.description,
            date: dateTime.toISOString(),
            tutorId: currentUser.id,
            tutorName: currentUser.fullName,
            maxParticipants: Number(eventForm.maxParticipants),
            participants: [],
            waitingList: []
        });
    }

    setIsModalOpen(false);
  };

  const handleAssignStudent = () => {
     if (editingEventId && studentToAssign) {
         assignUserToEvent(editingEventId, studentToAssign);
         setStudentToAssign('');
     }
  };

  const getCapacityColor = (current: number, max: number) => {
    const percentage = current / max;
    if (percentage >= 1) return 'bg-red-500';
    if (percentage >= 0.8) return 'bg-yellow-500';
    return 'bg-green-500';
  };

  const activeEvent = tutorEvents.find(e => e.id === editingEventId);
  const activeEventParticipants = activeEvent ? users.filter(u => activeEvent.participants.includes(u.id)) : [];
  // Available students to assign: Role is student, and not already in participants
  const availableStudents = users.filter(u => u.role === Role.STUDENT && activeEvent && !activeEvent.participants.includes(u.id));

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-6">
        <div>
           <h1 className="text-3xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <GraduationCap /> Tutor Events
          </h1>
          <p className="text-gray-500 dark:text-gray-400 mt-1">
             Exclusive sessions hosted by our Murid Bibilung. First come, first served!
          </p>
        </div>

        {canCreate && (
          <button 
            onClick={openCreateModal}
            className="bg-primary text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-600 transition"
          >
            <Plus size={18} /> Create Event
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {tutorEvents.map(event => {
          const isFull = event.participants.length >= event.maxParticipants;
          const isJoined = currentUser ? event.participants.includes(currentUser.id) : false;
          const isWaitlisted = currentUser ? (event.waitingList || []).includes(currentUser.id) : false;

          const isCreator = currentUser?.id === event.tutorId;
          const canManage = isCreator || currentUser?.role === Role.ADMIN || currentUser?.role === Role.KURIKULUM;
          const eventDate = new Date(event.date);

          // Get participant objects to display names
          const joinedUsers = users.filter(u => event.participants.includes(u.id));
          const waitingUsers = users.filter(u => (event.waitingList || []).includes(u.id));

          return (
            <div key={event.id} className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col overflow-hidden transition hover:shadow-md">
               <div className="p-6 flex-1 flex flex-col">
                  <div className="flex justify-between items-start mb-3">
                     <span className="bg-purple-100 text-purple-800 text-xs font-bold px-2 py-1 rounded dark:bg-purple-900/30 dark:text-purple-300 uppercase tracking-wide">
                        Bibilung Class
                     </span>
                     <div className="flex gap-1">
                       <button onClick={() => openViewModal(event)} className="text-gray-400 hover:text-primary transition p-1" title="View Details">
                           <Eye size={16} />
                       </button>
                       {canManage && (
                         <>
                           <button onClick={() => openEditModal(event)} className="text-gray-400 hover:text-blue-500 transition p-1" title="Edit">
                              <Edit size={16} />
                           </button>
                           <button onClick={() => deleteTutorEvent(event.id)} className="text-gray-400 hover:text-red-500 transition p-1" title="Delete">
                             <Trash2 size={16} />
                           </button>
                         </>
                       )}
                     </div>
                  </div>

                  <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-2">{event.title}</h3>
                  <p className="text-gray-600 dark:text-gray-300 text-sm mb-4 line-clamp-2">{event.description}</p>

                  <div className="space-y-2 text-sm text-gray-500 dark:text-gray-400 mb-6">
                     <div className="flex items-center gap-2">
                        <User size={16} className="text-primary" />
                        <span>Tutor: <span className="font-semibold text-gray-700 dark:text-gray-200">{event.tutorName}</span></span>
                     </div>
                     <div className="flex items-center gap-2">
                        <Calendar size={16} className="text-primary" />
                        <span>{eventDate.toLocaleDateString()}</span>
                     </div>
                     <div className="flex items-center gap-2">
                        <Clock size={16} className="text-primary" />
                        <span>{eventDate.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                     </div>
                  </div>

                  {/* Participant List */}
                  <div className="mt-auto pt-4 border-t border-gray-100 dark:border-gray-700">
                     <div className="flex items-center gap-2 mb-2 text-xs font-semibold text-gray-500 dark:text-gray-400">
                        <Users size={14} /> Registered Students ({joinedUsers.length})
                     </div>
                     <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto custom-scrollbar">
                        {joinedUsers.length === 0 ? (
                           <span className="text-xs text-gray-400 italic">No participants yet.</span>
                        ) : (
                           joinedUsers.map(u => (
                             <div key={u.id} className="flex items-center gap-1.5 bg-gray-100 dark:bg-gray-700/50 px-2 py-1 rounded-full border border-gray-200 dark:border-gray-600" title={u.fullName}>
                                <div className="w-5 h-5 rounded-full bg-primary/20 text-primary flex items-center justify-center text-[10px] font-bold">
                                   {u.username.substring(0,2).toUpperCase()}
                                </div>
                                <span className="text-xs text-gray-700 dark:text-gray-300 max-w-[80px] truncate">{u.fullName.split(' ')[0]}</span> 
                             </div>
                           ))
                        )}
                     </div>
                  </div>

                  {/* Waiting List - Only Visible to Admin/Kurikulum/Owner */}
                  {canManage && waitingUsers.length > 0 && (
                      <div className="mt-4 pt-4 border-t border-dashed border-gray-200 dark:border-gray-600">
                          <div className="flex items-center gap-2 mb-2 text-xs font-semibold text-yellow-600 dark:text-yellow-500">
                             <ClipboardList size={14} /> Waiting List ({waitingUsers.length})
                          </div>
                          <div className="space-y-2">
                              {waitingUsers.map(u => (
                                  <div key={u.id} className="flex justify-between items-center text-xs bg-yellow-50 dark:bg-yellow-900/10 p-2 rounded">
                                      <span className="text-gray-700 dark:text-gray-300">{u.fullName}</span>
                                      <button 
                                        onClick={() => promoteFromWaitingList(event.id, u.id)}
                                        className="flex items-center gap-1 bg-white dark:bg-gray-800 border border-green-200 text-green-600 px-2 py-1 rounded shadow-sm hover:bg-green-50 transition"
                                        title="Assign to class"
                                      >
                                          <UserPlus size={12} /> Assign
                                      </button>
                                  </div>
                              ))}
                          </div>
                      </div>
                  )}
               </div>

               <div className="bg-gray-50 dark:bg-gray-750 p-4 border-t dark:border-gray-700">
                  <div className="flex justify-between items-center mb-3 text-sm">
                     <span className="font-medium text-gray-600 dark:text-gray-300">Quota</span>
                     <span className={`${isFull ? 'text-red-500' : 'text-green-600'} font-bold`}>
                        {event.participants.length} / {event.maxParticipants}
                     </span>
                  </div>
                  <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2 mb-4 overflow-hidden">
                     <div 
                        className={`h-2 rounded-full transition-all duration-500 ${getCapacityColor(event.participants.length, event.maxParticipants)}`} 
                        style={{ width: `${(event.participants.length / event.maxParticipants) * 100}%` }}
                     ></div>
                  </div>

                  {isJoined ? (
                     <button 
                        onClick={() => leaveTutorEvent(event.id)}
                        className="w-full py-2 rounded-lg border border-red-200 text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 dark:border-red-900 dark:text-red-400 flex items-center justify-center gap-2 transition"
                     >
                        <LogOut size={18} /> Leave Class
                     </button>
                  ) : isWaitlisted ? (
                    <button 
                        onClick={() => leaveTutorEvent(event.id)}
                        className="w-full py-2 rounded-lg border border-yellow-200 text-yellow-600 hover:bg-yellow-50 dark:hover:bg-yellow-900/20 dark:border-yellow-900 dark:text-yellow-400 flex items-center justify-center gap-2 transition"
                     >
                        <LogOut size={18} /> Leave Waitlist
                     </button>
                  ) : (
                     <button 
                        onClick={() => joinTutorEvent(event.id)}
                        disabled={!canJoin}
                        className={`w-full py-2 rounded-lg text-white flex items-center justify-center gap-2 transition font-medium
                           ${!canJoin 
                              ? 'bg-gray-300 dark:bg-gray-700 cursor-not-allowed text-gray-500' 
                              : isFull 
                                ? 'bg-yellow-500 hover:bg-yellow-600 text-white' 
                                : 'bg-primary hover:bg-blue-600 shadow-sm hover:shadow'
                           }
                        `}
                     >
                        {!canJoin ? 'Students Only' : isFull ? 'Join Waitlist' : <><LogIn size={18} /> Join Class</>}
                     </button>
                  )}
               </div>
            </div>
          );
        })}
      </div>

      {tutorEvents.length === 0 && (
         <div className="text-center py-20 text-gray-400 bg-gray-50 dark:bg-gray-800/50 rounded-xl border border-dashed border-gray-200 dark:border-gray-700 mt-8">
            <GraduationCap size={48} className="mx-auto mb-4 opacity-50" />
            <p className="text-lg font-medium">No active tutor events yet.</p>
            {canCreate && <p className="text-sm">Be the first Murid Bibilung to create one!</p>}
         </div>
      )}

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 animate-fade-in">
          <div className="bg-white dark:bg-gray-800 p-6 rounded-2xl w-full max-w-md shadow-2xl transform scale-100 transition-all max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-4">
               <h3 className="text-xl font-bold dark:text-white flex items-center gap-2">
                 {viewOnly ? (
                    <><Eye className="text-primary" size={24} /> Event Details</>
                 ) : isEditMode ? (
                    <><Edit className="text-primary" size={24} /> Edit Tutor Event</>
                 ) : (
                    <><Plus className="text-primary" size={24} /> Create Tutor Event</>
                 )}
               </h3>
               <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-white">
                 <X size={24} />
               </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                 <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Topic / Title</label>
                 <input 
                  disabled={viewOnly}
                  className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:ring-2 focus:ring-primary outline-none disabled:opacity-70 disabled:cursor-not-allowed"
                  placeholder="e.g. Advanced CSS Grid"
                  required
                  value={eventForm.title}
                  onChange={e => setEventForm({...eventForm, title: e.target.value})}
                />
              </div>

              <div>
                 <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Description</label>
                 <textarea 
                  disabled={viewOnly}
                  className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:ring-2 focus:ring-primary outline-none disabled:opacity-70 disabled:cursor-not-allowed"
                  placeholder="What will be discussed?"
                  rows={3}
                  required
                  value={eventForm.description}
                  onChange={e => setEventForm({...eventForm, description: e.target.value})}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Date</label>
                    <input 
                     disabled={viewOnly}
                     type="date"
                     className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:ring-2 focus:ring-primary outline-none disabled:opacity-70 disabled:cursor-not-allowed"
                     required
                     value={eventForm.date}
                     onChange={e => setEventForm({...eventForm, date: e.target.value})}
                   />
                 </div>
                 <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Time</label>
                    <input 
                     disabled={viewOnly}
                     type="time"
                     className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:ring-2 focus:ring-primary outline-none disabled:opacity-70 disabled:cursor-not-allowed"
                     required
                     value={eventForm.time}
                     onChange={e => setEventForm({...eventForm, time: e.target.value})}
                   />
                 </div>
              </div>

              <div>
                 <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Max Participants</label>
                 <input 
                  disabled={viewOnly}
                  type="number"
                  min="1"
                  max="50"
                  className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600 dark:text-white focus:ring-2 focus:ring-primary outline-none disabled:opacity-70 disabled:cursor-not-allowed"
                  required
                  value={eventForm.maxParticipants}
                  onChange={e => setEventForm({...eventForm, maxParticipants: Number(e.target.value)})}
                />
              </div>

              {/* Participant Management Section */}
              {(isEditMode || viewOnly) && activeEvent && (
                 <div className="mt-4 pt-4 border-t border-gray-200 dark:border-gray-700">
                    <h4 className="font-bold text-gray-800 dark:text-white mb-2 flex items-center justify-between">
                       <span>Participants ({activeEventParticipants.length}/{eventForm.maxParticipants})</span>
                    </h4>

                    {/* Add Student Control - Only in Edit Mode */}
                    {isEditMode && (
                        <div className="flex gap-2 mb-3">
                           <select 
                              className="flex-1 p-2 border rounded text-sm dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                              value={studentToAssign}
                              onChange={e => setStudentToAssign(e.target.value)}
                           >
                              <option value="">Select Student to Assign...</option>
                              {availableStudents.map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}
                           </select>
                           <button 
                              type="button"
                              onClick={handleAssignStudent}
                              disabled={!studentToAssign}
                              className="bg-green-600 text-white px-3 py-1 rounded text-sm hover:bg-green-700 disabled:opacity-50 disabled:cursor-not-allowed"
                           >
                              <Plus size={16} /> Add
                           </button>
                        </div>
                    )}

                    <div className="space-y-2 max-h-32 overflow-y-auto custom-scrollbar bg-gray-50 dark:bg-gray-900/50 p-2 rounded">
                       {activeEventParticipants.length === 0 ? (
                           <p className="text-xs text-gray-400 italic text-center">No participants yet.</p>
                       ) : (
                           activeEventParticipants.map(p => (
                               <div key={p.id} className="flex justify-between items-center text-sm p-1 hover:bg-gray-100 dark:hover:bg-gray-800 rounded">
                                   <div className="flex items-center gap-2">
                                       <div className="w-5 h-5 rounded-full bg-primary/20 text-primary flex items-center justify-center text-[10px] font-bold">
                                            {p.username.substring(0,2).toUpperCase()}
                                       </div>
                                       <span className="text-gray-700 dark:text-gray-300">{p.fullName}</span>
                                   </div>
                                   {isEditMode && (
                                       <button 
                                          type="button" 
                                          onClick={() => kickFromEvent(activeEvent.id, p.id)}
                                          className="text-red-500 hover:bg-red-50 p-1 rounded"
                                          title="Remove from event"
                                       >
                                           <X size={14} />
                                       </button>
                                   )}
                               </div>
                           ))
                       )}
                    </div>
                 </div>
              )}

              {!viewOnly && (
                <div className="flex justify-end gap-2 pt-2">
                  <button type="button" onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg transition">Cancel</button>
                  <button type="submit" className="px-6 py-2 bg-primary text-white rounded-lg shadow hover:bg-blue-600 transition">
                      {isEditMode ? 'Update Event' : 'Create Event'}
                  </button>
                </div>
              )}
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, Role, Announcement, Task, ScheduleItem, VideoMaterial, ActivityLog, Subject, DocumentMaterial, TutorEvent } from '../types';
import { generateUsers, initialAnnouncements, initialTasks, initialSchedule, initialVideos, initialSubjects, initialMaterials, initialTutorEvents } from '../services/mockData';
import { supabase, isSupabaseConfigured } from '../services/supabaseClient';

interface StoreContextType {
  currentUser: User | null;
  users: User[];
  subjects: Subject[];
  announcements: Announcement[];
  tasks: Task[];
  schedule: ScheduleItem[];
  videos: VideoMaterial[];
  materials: DocumentMaterial[];
  tutorEvents: TutorEvent[];
  activityLog: ActivityLog[];
  isDarkMode: boolean;
  isLoading: boolean;

  toggleDarkMode: () => void;
  login: (username: string, password: string) => boolean;
  loginWithGoogle: (email: string, name: string, googleId: string) => void;
  logout: () => void;

  // Data manipulation
  addAnnouncement: (announcement: Announcement) => void;
  addTask: (task: Task) => void;
  toggleTaskCompletion: (taskId: string) => void;

  addSubject: (subject: Subject) => void;
  deleteSubject: (id: string) => void;

  addScheduleItem: (item: ScheduleItem) => void;
  deleteScheduleItem: (id: string) => void;

  addVideo: (video: VideoMaterial) => void;
  deleteVideo: (id: string) => void;

  addMaterial: (material: DocumentMaterial) => void;
  deleteMaterial: (id: string) => void;

  addTutorEvent: (event: TutorEvent) => void;
  editTutorEvent: (id: string, updates: Partial<TutorEvent>) => void;
  deleteTutorEvent: (id: string) => void;
  joinTutorEvent: (eventId: string) => void;
  leaveTutorEvent: (eventId: string) => void;
  promoteFromWaitingList: (eventId: string, userId: string) => void;
  assignUserToEvent: (eventId: string, userId: string) => void;
  kickFromEvent: (eventId: string, userId: string) => void;

  updateUserRole: (userId: string, role: Role) => void;
  updateUserStatus: (userId: string, isActive: boolean) => void;
  updateUserProfile: (userId: string, data: { fullName?: string, password?: string }) => void;

  updateSeat: (userId: string, seatIndex: number | null) => void;
  resetSeats: () => void;
  randomizeSeats: () => void;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider = ({ children }: { children?: ReactNode }) => {
  // Initialize currentUser from localStorage if available
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const savedUser = localStorage.getItem('classSync_currentUser');
    return savedUser ? JSON.parse(savedUser) : null;
  });

  // Data States
  const [users, setUsers] = useState<User[]>([]);
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [schedule, setSchedule] = useState<ScheduleItem[]>([]);
  const [videos, setVideos] = useState<VideoMaterial[]>([]);
  const [materials, setMaterials] = useState<DocumentMaterial[]>([]);
  const [tutorEvents, setTutorEvents] = useState<TutorEvent[]>([]);
  const [activityLog, setActivityLog] = useState<ActivityLog[]>([]);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  // --- Initial Data Fetching ---
  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);

      // 1. Check if Supabase is configured
      if (!isSupabaseConfigured()) {
        console.warn("Supabase credentials missing. Falling back to local/mock data.");
        loadLocalData();
        setIsLoading(false);
        return;
      }

      try {
        // 2. Fetch Users
        const { data: dbUsers, error: userError } = await supabase.from('users').select('*');
        if (dbUsers && dbUsers.length > 0) {
          setUsers(dbUsers);
        } else {
          // Seed initial users if DB is empty
          const seedUsers = generateUsers();
          await supabase.from('users').insert(seedUsers);
          setUsers(seedUsers);
        }

        // 3. Fetch Subjects
        const { data: dbSubjects } = await supabase.from('subjects').select('*');
        setSubjects(dbSubjects?.length ? dbSubjects : []);

        // 4. Fetch Announcements
        const { data: dbAnnounce } = await supabase.from('announcements').select('*').order('date', { ascending: false });
        setAnnouncements(dbAnnounce?.length ? dbAnnounce : []);

        // 5. Fetch Tasks
        const { data: dbTasks } = await supabase.from('tasks').select('*').order('deadline', { ascending: true });
        setTasks(dbTasks?.length ? dbTasks : []);

        // 6. Fetch Schedule
        const { data: dbSchedule } = await supabase.from('schedule').select('*');
        setSchedule(dbSchedule?.length ? dbSchedule : []);

        // 7. Fetch Videos
        const { data: dbVideos } = await supabase.from('videos').select('*');
        setVideos(dbVideos?.length ? dbVideos : []);

        // 8. Fetch Materials
        const { data: dbMaterials } = await supabase.from('materials').select('*');
        setMaterials(dbMaterials?.length ? dbMaterials : []);

        // 9. Fetch Tutor Events
        const { data: dbEvents } = await supabase.from('tutor_events').select('*');
        setTutorEvents(dbEvents?.length ? dbEvents : []);

        // 10. Fetch Logs
        const { data: dbLogs } = await supabase.from('activity_logs').select('*').order('timestamp', { ascending: false }).limit(50);
        setActivityLog(dbLogs?.length ? dbLogs : []);

      } catch (error) {
        console.error("Error fetching data from Supabase:", error);
        loadLocalData(); // Fallback on error
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  const loadLocalData = () => {
    // Fallback logic from previous version
    const storedUsers = localStorage.getItem('classSync_users');
    setUsers(storedUsers ? JSON.parse(storedUsers) : generateUsers());
    const storedSubjects = localStorage.getItem('classSync_subjects');
    setSubjects(storedSubjects ? JSON.parse(storedSubjects) : initialSubjects);
    // ... load others similarly or just use mock defaults
    if (!storedUsers) setUsers(generateUsers());
    if (!storedSubjects) setSubjects(initialSubjects);
    setAnnouncements(initialAnnouncements);
    setTasks(initialTasks);
    setSchedule(initialSchedule);
    setVideos(initialVideos);
    setMaterials(initialMaterials);
    setTutorEvents(initialTutorEvents);
  };

  // --- Persistence Helper ---
  // We no longer use useEffect to persist to localStorage. 
  // Instead, we call Supabase in the action methods.

  // Dark Mode
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  const logActivity = async (action: string) => {
    if (!currentUser) return;
    const log: ActivityLog = {
      id: Date.now().toString(),
      userId: currentUser.id,
      action: `${currentUser.username} (${currentUser.role}): ${action}`,
      timestamp: new Date().toISOString()
    };
    setActivityLog(prev => [log, ...prev]);
    if (isSupabaseConfigured()) {
       await supabase.from('activity_logs').insert(log);
    }
  };

  const login = (u: string, p: string) => {
    const user = users.find(usr => usr.username === u && usr.password === p);
    if (user && user.isActive) {
      setCurrentUser(user);
      localStorage.setItem('classSync_currentUser', JSON.stringify(user)); // Persist session
      logActivity(`Logged in`);
      return true;
    }
    return false;
  };

  const loginWithGoogle = async (email: string, name: string, googleId: string) => {
    let user = users.find(u => u.username === email);

    if (!user) {
      user = {
        id: `g_${googleId}`,
        username: email,
        fullName: name,
        role: Role.STUDENT, 
        isActive: true,
        password: '', 
        seatIndex: null
      };
      setUsers(prev => [...prev, user!]);
      if (isSupabaseConfigured()) {
        await supabase.from('users').insert(user);
      }
    }

    if (user && user.isActive) {
      setCurrentUser(user);
      localStorage.setItem('classSync_currentUser', JSON.stringify(user)); // Persist session
      logActivity(`Logged in via Google`);
    }
  };

  const logout = () => {
    if (currentUser) {
      logActivity(`Logged out`);
    }
    setCurrentUser(null);
    localStorage.removeItem('classSync_currentUser'); // Clear session
  };

  // --- Actions with Supabase Integration ---

  const addAnnouncement = async (item: Announcement) => {
    setAnnouncements([item, ...announcements]);
    if (isSupabaseConfigured()) await supabase.from('announcements').insert(item);
    logActivity(`Added announcement: ${item.title}`);
  };

  const addTask = async (item: Task) => {
    setTasks([item, ...tasks]);
    if (isSupabaseConfigured()) await supabase.from('tasks').insert(item);
    logActivity(`Added task: ${item.title}`);
  };

  const toggleTaskCompletion = async (taskId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;
    const newStatus = !task.isCompleted;

    setTasks(tasks.map(t => t.id === taskId ? { ...t, isCompleted: newStatus } : t));

    if (isSupabaseConfigured()) {
      await supabase.from('tasks').update({ isCompleted: newStatus }).eq('id', taskId);
    }
  };

  const addSubject = async (subject: Subject) => {
    setSubjects([...subjects, subject]);
    if (isSupabaseConfigured()) await supabase.from('subjects').insert(subject);
    logActivity(`Added subject: ${subject.name}`);
  }

  const deleteSubject = async (id: string) => {
    setSubjects(subjects.filter(s => s.id !== id));
    if (isSupabaseConfigured()) await supabase.from('subjects').delete().eq('id', id);
    logActivity(`Deleted subject ID: ${id}`);
  }

  const addScheduleItem = async (item: ScheduleItem) => {
    setSchedule([...schedule, item]);
    if (isSupabaseConfigured()) await supabase.from('schedule').insert(item);
    logActivity(`Added schedule item for ${item.day}`);
  }

  const deleteScheduleItem = async (id: string) => {
    setSchedule(schedule.filter(s => s.id !== id));
    if (isSupabaseConfigured()) await supabase.from('schedule').delete().eq('id', id);
    logActivity(`Deleted schedule item ID: ${id}`);
  }

  const addVideo = async (video: VideoMaterial) => {
    setVideos([video, ...videos]);
    if (isSupabaseConfigured()) await supabase.from('videos').insert(video);
    logActivity(`Added video: ${video.title}`);
  }

  const deleteVideo = async (id: string) => {
    setVideos(videos.filter(v => v.id !== id));
    if (isSupabaseConfigured()) await supabase.from('videos').delete().eq('id', id);
    logActivity(`Deleted video ID: ${id}`);
  }

  const addMaterial = async (material: DocumentMaterial) => {
    setMaterials([material, ...materials]);
    if (isSupabaseConfigured()) await supabase.from('materials').insert(material);
    logActivity(`Added material: ${material.title}`);
  }

  const deleteMaterial = async (id: string) => {
    setMaterials(materials.filter(m => m.id !== id));
    if (isSupabaseConfigured()) await supabase.from('materials').delete().eq('id', id);
    logActivity(`Deleted material ID: ${id}`);
  }

  const addTutorEvent = async (event: TutorEvent) => {
    setTutorEvents([event, ...tutorEvents]);
    if (isSupabaseConfigured()) await supabase.from('tutor_events').insert(event);
    logActivity(`Added tutor event: ${event.title}`);
  };

  const editTutorEvent = async (id: string, updates: Partial<TutorEvent>) => {
    setTutorEvents(prev => prev.map(ev => ev.id === id ? { ...ev, ...updates } : ev));
    if (isSupabaseConfigured()) await supabase.from('tutor_events').update(updates).eq('id', id);
    logActivity(`Edited tutor event ID: ${id}`);
  };

  const deleteTutorEvent = async (id: string) => {
    setTutorEvents(tutorEvents.filter(e => e.id !== id));
    if (isSupabaseConfigured()) await supabase.from('tutor_events').delete().eq('id', id);
    logActivity(`Deleted tutor event ID: ${id}`);
  };

  const joinTutorEvent = async (eventId: string) => {
    if (!currentUser) return;
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    // Check if already in participants or waiting list
    if (event.participants.includes(currentUser.id) || (event.waitingList && event.waitingList.includes(currentUser.id))) {
      return;
    }

    if (event.participants.length < event.maxParticipants) {
      // Join as participant
      const newParticipants = [...event.participants, currentUser.id];
      setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, participants: newParticipants } : ev));

      if (isSupabaseConfigured()) {
        await supabase.from('tutor_events').update({ participants: newParticipants }).eq('id', eventId);
      }
      logActivity(`Joined tutor event ID: ${eventId}`);
    } else {
      // Join waiting list
      const currentWaitingList = event.waitingList || [];
      const newWaitingList = [...currentWaitingList, currentUser.id];
      setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, waitingList: newWaitingList } : ev));

      if (isSupabaseConfigured()) {
        await supabase.from('tutor_events').update({ waitingList: newWaitingList }).eq('id', eventId);
      }
      logActivity(`Joined waiting list for event ID: ${eventId}`);
    }
  };

  const leaveTutorEvent = async (eventId: string) => {
    if (!currentUser) return;
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    const isParticipant = event.participants.includes(currentUser.id);
    const isWaitlisted = event.waitingList && event.waitingList.includes(currentUser.id);

    if (isParticipant) {
        const newParticipants = event.participants.filter(id => id !== currentUser.id);
        setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, participants: newParticipants } : ev));
        if (isSupabaseConfigured()) {
            await supabase.from('tutor_events').update({ participants: newParticipants }).eq('id', eventId);
        }
        logActivity(`Left tutor event ID: ${eventId}`);
    } else if (isWaitlisted) {
        const newWaitingList = (event.waitingList || []).filter(id => id !== currentUser.id);
        setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, waitingList: newWaitingList } : ev));
        if (isSupabaseConfigured()) {
            await supabase.from('tutor_events').update({ waitingList: newWaitingList }).eq('id', eventId);
        }
        logActivity(`Left waiting list for event ID: ${eventId}`);
    }
  };

  const promoteFromWaitingList = async (eventId: string, userId: string) => {
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    // Remove from waiting list
    const newWaitingList = (event.waitingList || []).filter(id => id !== userId);

    // Add to participants if not already there
    let newParticipants = event.participants;
    if (!event.participants.includes(userId)) {
       newParticipants = [...event.participants, userId];
    }

    setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { 
        ...ev, 
        waitingList: newWaitingList,
        participants: newParticipants
    } : ev));

    if (isSupabaseConfigured()) {
       await supabase.from('tutor_events').update({ 
           waitingList: newWaitingList,
           participants: newParticipants
       }).eq('id', eventId);
    }
    logActivity(`Promoted user ${userId} from waiting list in event ${eventId}`);
  };

  const assignUserToEvent = async (eventId: string, userId: string) => {
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    if (event.participants.includes(userId)) return;

    const newWaitingList = (event.waitingList || []).filter(id => id !== userId);
    const newParticipants = [...event.participants, userId];

    setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { 
        ...ev, 
        waitingList: newWaitingList,
        participants: newParticipants
    } : ev));

    if (isSupabaseConfigured()) {
       await supabase.from('tutor_events').update({ 
           waitingList: newWaitingList,
           participants: newParticipants
       }).eq('id', eventId);
    }
    logActivity(`Assigned user ${userId} to event ${eventId}`);
  };

  const kickFromEvent = async (eventId: string, userId: string) => {
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    const newParticipants = event.participants.filter(id => id !== userId);
    setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, participants: newParticipants } : ev));

    if (isSupabaseConfigured()) {
        await supabase.from('tutor_events').update({ participants: newParticipants }).eq('id', eventId);
    }
    logActivity(`Removed user ${userId} from event ${eventId}`);
  };

  const updateUserRole = async (userId: string, role: Role) => {
    setUsers(users.map(u => u.id === userId ? { ...u, role } : u));
    if (isSupabaseConfigured()) await supabase.from('users').update({ role }).eq('id', userId);
    logActivity(`Updated user ${userId} to role ${role}`);
  };

  const updateUserStatus = async (userId: string, isActive: boolean) => {
    setUsers(users.map(u => u.id === userId ? { ...u, isActive } : u));
    if (isSupabaseConfigured()) await supabase.from('users').update({ isActive }).eq('id', userId);
    logActivity(`Updated user ${userId} active status to ${isActive}`);
  };

  const updateUserProfile = async (userId: string, data: { fullName?: string, password?: string }) => {
    const updates: any = {};
    if (data.fullName) updates.fullName = data.fullName;
    if (data.password) updates.password = data.password;

    setUsers(users.map(u => {
      if (u.id === userId) {
        return { ...u, ...updates };
      }
      return u;
    }));

    if (currentUser && currentUser.id === userId) {
      const updatedUser = { ...currentUser, ...updates };
      setCurrentUser(updatedUser);
      localStorage.setItem('classSync_currentUser', JSON.stringify(updatedUser)); // Update persisted session
    }

    if (isSupabaseConfigured()) await supabase.from('users').update(updates).eq('id', userId);
    logActivity(`User ${userId} updated their profile`);
  };

  const updateSeat = async (userId: string, seatIndex: number | null) => {
    setUsers(prev => prev.map(u => {
      if (u.id === userId) return { ...u, seatIndex };
      if (seatIndex !== null && u.seatIndex === seatIndex) return { ...u, seatIndex: null };
      return u;
    }));

    // In DB we need to handle the swap carefully, but for now just update the target user
    // Ideally we update the old seat holder to null too if needed
    if (isSupabaseConfigured()) {
       if (seatIndex !== null) {
           // Clear anyone else on this seat
           await supabase.from('users').update({ seatIndex: null }).eq('seatIndex', seatIndex);
       }
       await supabase.from('users').update({ seatIndex }).eq('id', userId);
    }
    logActivity(`Updated seat for user ${userId}`);
  };

  const resetSeats = async () => {
     setUsers(prev => prev.map(u => ({ ...u, seatIndex: null })));
     if (isSupabaseConfigured()) await supabase.from('users').update({ seatIndex: null }).neq('id', '0'); // update all
     logActivity('Reset all seats');
  };

  const randomizeSeats = async () => {
    const students = users.filter(u => u.role === Role.STUDENT);
    const studentIds = students.map(u => u.id);
    const shuffled = [...studentIds].sort(() => Math.random() - 0.5);

    const updates = students.map(u => {
      const idx = shuffled.indexOf(u.id);
      return { id: u.id, seatIndex: idx < 35 ? idx : null };
    });

    // Optimistic update
    setUsers(prev => prev.map(u => {
      if (u.role === Role.STUDENT) {
        const up = updates.find(x => x.id === u.id);
        return { ...u, seatIndex: up ? up.seatIndex : null };
      }
      return u;
    }));

    if (isSupabaseConfigured()) {
        // Batch update is hard in REST without RPC, loop for now (not efficient but works for 35 users)
        for (const up of updates) {
            await supabase.from('users').update({ seatIndex: up.seatIndex }).eq('id', up.id);
        }
    }
    logActivity('Randomized seats');
  };

  return (
    <StoreContext.Provider value={{
      currentUser, users, subjects, announcements, tasks, schedule, videos, materials, tutorEvents, activityLog, isDarkMode, isLoading,
      toggleDarkMode, login, loginWithGoogle, logout, 
      addAnnouncement, addTask, toggleTaskCompletion,
      addSubject, deleteSubject, addScheduleItem, deleteScheduleItem,
      addVideo, deleteVideo,
      addMaterial, deleteMaterial,
      addTutorEvent, editTutorEvent, deleteTutorEvent, joinTutorEvent, leaveTutorEvent, promoteFromWaitingList, assignUserToEvent, kickFromEvent,
      updateUserRole, updateUserStatus, updateUserProfile,
      updateSeat, resetSeats, randomizeSeats
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error("useStore must be used within StoreProvider");
  return context;
};

import React from 'react';
import { HashRouter, Routes, Route, Navigate, Outlet } from 'react-router-dom';
import { StoreProvider, useStore } from './context/Store';
import { Sidebar } from './components/Sidebar';
import { Login } from './pages/Login';
import { Dashboard } from './pages/Dashboard';
import { Assignments } from './pages/Assignments';
import { SeatingPlan } from './pages/SeatingPlan';
import { AdminPanel } from './pages/AdminPanel';
import { Subjects } from './pages/Subjects';
import { Videos } from './pages/Videos';
import { Materials } from './pages/Materials';
import { Profile } from './pages/Profile';
import { TutorEvents } from './pages/TutorEvents';
import { Schedule } from './pages/Schedule';
import { Role } from './types';
import { Sun, Moon, Loader2 } from 'lucide-react';

const Layout = () => {
  const { currentUser, isLoading, isDarkMode, toggleDarkMode } = useStore();

  // Show loader while checking session/data to prevent flickering or premature redirect
  if (isLoading) {
    return (
      <div className="flex h-screen w-full items-center justify-center bg-gray-50 dark:bg-gray-900 transition-colors">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="animate-spin text-primary" size={48} />
          <p className="text-gray-500 dark:text-gray-400 font-medium">Loading ClassSync...</p>
        </div>
      </div>
    );
  }

  if (!currentUser) return <Navigate to="/login" />;

  return (
    <div className="flex min-h-screen bg-gray-50 dark:bg-gray-900 transition-colors duration-200">
      <Sidebar />
      <main className="flex-1 ml-64 p-4 relative">
        <button 
          onClick={toggleDarkMode}
          className="absolute top-4 right-8 p-2 rounded-full bg-gray-200 dark:bg-gray-700 text-gray-800 dark:text-yellow-400 z-10 hover:opacity-80 transition"
        >
          {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
        </button>
        <div className="mt-8 md:mt-0">
           <Outlet />
        </div>
      </main>
    </div>
  );
};

const ProtectedRoute = ({ children, roles }: { children?: React.ReactNode, roles?: Role[] }) => {
  const { currentUser, isLoading } = useStore();

  if (isLoading) return null; // Let Layout handle loading UI
  if (!currentUser) return <Navigate to="/login" />;

  if (roles && !roles.includes(currentUser.role)) {
     return (
       <div className="flex flex-col items-center justify-center h-full text-center mt-20">
         <h1 className="text-6xl font-bold text-gray-300">403</h1>
         <p className="text-xl text-gray-500 mt-4">Access Forbidden</p>
         <p className="text-gray-400">You do not have permission to view this page.</p>
       </div>
     );
  }

  return <>{children}</>;
};

const App = () => {
  return (
    <StoreProvider>
      <HashRouter>
        <Routes>
          <Route path="/login" element={<Login />} />

          <Route path="/" element={<Layout />}>
            <Route index element={<Navigate to="/dashboard" />} />
            <Route path="dashboard" element={<Dashboard />} />
            <Route path="assignments" element={<Assignments />} />
            <Route path="seating" element={<SeatingPlan />} />
            <Route path="subjects" element={<Subjects />} />
            <Route path="videos" element={<Videos />} />
            <Route path="materials" element={<Materials />} />
            <Route path="tutor-events" element={<TutorEvents />} />
            <Route path="profile" element={<Profile />} />
            <Route path="schedule" element={<Schedule />} />

            <Route path="admin" element={
              <ProtectedRoute roles={[Role.ADMIN]}>
                <AdminPanel />
              </ProtectedRoute>
            } />
          </Route>
        </Routes>
      </HashRouter>
    </StoreProvider>
  );
};

export default App;

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, Role, Announcement, Task, ScheduleItem, VideoMaterial, ActivityLog, Subject, DocumentMaterial, TutorEvent } from '../types';
import { generateUsers, initialAnnouncements, initialTasks, initialSchedule, initialVideos, initialSubjects, initialMaterials, initialTutorEvents } from '../services/mockData';
import { supabase, isSupabaseConfigured } from '../services/supabaseClient';

interface StoreContextType {
  currentUser: User | null;
  users: User[];
  subjects: Subject[];
  announcements: Announcement[];
  tasks: Task[];
  schedule: ScheduleItem[];
  videos: VideoMaterial[];
  materials: DocumentMaterial[];
  tutorEvents: TutorEvent[];
  activityLog: ActivityLog[];
  isDarkMode: boolean;
  isLoading: boolean;

  toggleDarkMode: () => void;
  login: (username: string, password: string) => boolean;
  loginWithGoogle: (email: string, name: string, googleId: string) => void;
  logout: () => void;

  // Data manipulation
  addAnnouncement: (announcement: Announcement) => void;
  addTask: (task: Task) => void;
  toggleTaskCompletion: (taskId: string) => void;

  addSubject: (subject: Subject) => void;
  deleteSubject: (id: string) => void;

  addScheduleItem: (item: ScheduleItem) => void;
  deleteScheduleItem: (id: string) => void;

  addVideo: (video: VideoMaterial) => void;
  deleteVideo: (id: string) => void;

  addMaterial: (material: DocumentMaterial) => void;
  deleteMaterial: (id: string) => void;

  addTutorEvent: (event: TutorEvent) => void;
  editTutorEvent: (id: string, updates: Partial<TutorEvent>) => void;
  deleteTutorEvent: (id: string) => void;
  joinTutorEvent: (eventId: string) => void;
  leaveTutorEvent: (eventId: string) => void;
  promoteFromWaitingList: (eventId: string, userId: string) => void;
  assignUserToEvent: (eventId: string, userId: string) => void;
  kickFromEvent: (eventId: string, userId: string) => void;

  updateUserRole: (userId: string, role: Role) => void;
  updateUserStatus: (userId: string, isActive: boolean) => void;
  updateUserProfile: (userId: string, data: { fullName?: string, password?: string }) => void;

  updateSeat: (userId: string, seatIndex: number | null) => void;
  resetSeats: () => void;
  randomizeSeats: () => void;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider = ({ children }: { children?: ReactNode }) => {
  // Initialize currentUser from localStorage synchronously to avoid initial null state
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    try {
      const savedUser = localStorage.getItem('classSync_currentUser');
      return savedUser ? JSON.parse(savedUser) : null;
    } catch (error) {
      console.error("Error parsing session:", error);
      return null;
    }
  });

  // Data States
  const [users, setUsers] = useState<User[]>([]);
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [schedule, setSchedule] = useState<ScheduleItem[]>([]);
  const [videos, setVideos] = useState<VideoMaterial[]>([]);
  const [materials, setMaterials] = useState<DocumentMaterial[]>([]);
  const [tutorEvents, setTutorEvents] = useState<TutorEvent[]>([]);
  const [activityLog, setActivityLog] = useState<ActivityLog[]>([]);

  const [isDarkMode, setIsDarkMode] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  // Sync currentUser changes to localStorage
  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('classSync_currentUser', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('classSync_currentUser');
    }
  }, [currentUser]);

  // --- Initial Data Fetching ---
  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);

      // 1. Check if Supabase is configured
      if (!isSupabaseConfigured()) {
        console.warn("Supabase credentials missing. Falling back to local/mock data.");
        loadLocalData();
        setIsLoading(false);
        return;
      }

      try {
        // 2. Fetch Users
        const { data: dbUsers, error: userError } = await supabase.from('users').select('*');
        if (dbUsers && dbUsers.length > 0) {
          setUsers(dbUsers);

          // Re-validate and sync session with latest DB data
          // We use the 'currentUser' from the closure (initial state) to check
          if (currentUser) {
            const freshUser = dbUsers.find((u: User) => u.id === currentUser.id);
            if (freshUser) {
               // Update session with fresh data (e.g. if role or name changed remotely)
               if (freshUser.isActive) {
                  setCurrentUser(freshUser); 
               } else {
                  // If user was suspended, log them out
                  setCurrentUser(null);
               }
            }
          }
        } else {
          // Seed initial users if DB is empty
          const seedUsers = generateUsers();
          await supabase.from('users').insert(seedUsers);
          setUsers(seedUsers);
        }

        // 3. Fetch Subjects
        const { data: dbSubjects } = await supabase.from('subjects').select('*');
        setSubjects(dbSubjects?.length ? dbSubjects : []);

        // 4. Fetch Announcements
        const { data: dbAnnounce } = await supabase.from('announcements').select('*').order('date', { ascending: false });
        setAnnouncements(dbAnnounce?.length ? dbAnnounce : []);

        // 5. Fetch Tasks
        const { data: dbTasks } = await supabase.from('tasks').select('*').order('deadline', { ascending: true });
        setTasks(dbTasks?.length ? dbTasks : []);

        // 6. Fetch Schedule
        const { data: dbSchedule } = await supabase.from('schedule').select('*');
        setSchedule(dbSchedule?.length ? dbSchedule : []);

        // 7. Fetch Videos
        const { data: dbVideos } = await supabase.from('videos').select('*');
        setVideos(dbVideos?.length ? dbVideos : []);

        // 8. Fetch Materials
        const { data: dbMaterials } = await supabase.from('materials').select('*');
        setMaterials(dbMaterials?.length ? dbMaterials : []);

        // 9. Fetch Tutor Events
        const { data: dbEvents } = await supabase.from('tutor_events').select('*');
        setTutorEvents(dbEvents?.length ? dbEvents : []);

        // 10. Fetch Logs
        const { data: dbLogs } = await supabase.from('activity_logs').select('*').order('timestamp', { ascending: false }).limit(50);
        setActivityLog(dbLogs?.length ? dbLogs : []);

      } catch (error) {
        console.error("Error fetching data from Supabase:", error);
        loadLocalData(); // Fallback on error
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []); // Empty dependency array ensures this runs once on mount

  const loadLocalData = () => {
    // Fallback logic from previous version
    const storedUsers = localStorage.getItem('classSync_users');
    setUsers(storedUsers ? JSON.parse(storedUsers) : generateUsers());
    const storedSubjects = localStorage.getItem('classSync_subjects');
    setSubjects(storedSubjects ? JSON.parse(storedSubjects) : initialSubjects);
    // ... load others similarly or just use mock defaults
    if (!storedUsers) setUsers(generateUsers());
    if (!storedSubjects) setSubjects(initialSubjects);
    setAnnouncements(initialAnnouncements);
    setTasks(initialTasks);
    setSchedule(initialSchedule);
    setVideos(initialVideos);
    setMaterials(initialMaterials);
    setTutorEvents(initialTutorEvents);
  };

  // Dark Mode
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  const logActivity = async (action: string) => {
    if (!currentUser) return;
    const log: ActivityLog = {
      id: Date.now().toString(),
      userId: currentUser.id,
      action: `${currentUser.username} (${currentUser.role}): ${action}`,
      timestamp: new Date().toISOString()
    };
    setActivityLog(prev => [log, ...prev]);
    if (isSupabaseConfigured()) {
       await supabase.from('activity_logs').insert(log);
    }
  };

  const login = (u: string, p: string) => {
    const user = users.find(usr => usr.username === u && usr.password === p);
    if (user && user.isActive) {
      setCurrentUser(user);
      // localStorage is handled by useEffect now
      logActivity(`Logged in`);
      return true;
    }
    return false;
  };

  const loginWithGoogle = async (email: string, name: string, googleId: string) => {
    let user = users.find(u => u.username === email);

    if (!user) {
      user = {
        id: `g_${googleId}`,
        username: email,
        fullName: name,
        role: Role.STUDENT, 
        isActive: true,
        password: '', 
        seatIndex: null
      };
      setUsers(prev => [...prev, user!]);
      if (isSupabaseConfigured()) {
        await supabase.from('users').insert(user);
      }
    }

    if (user && user.isActive) {
      setCurrentUser(user);
      logActivity(`Logged in via Google`);
    }
  };

  const logout = () => {
    if (currentUser) {
      logActivity(`Logged out`);
    }
    setCurrentUser(null);
    // localStorage removal handled by useEffect
  };

  // --- Actions with Supabase Integration ---

  const addAnnouncement = async (item: Announcement) => {
    setAnnouncements([item, ...announcements]);
    if (isSupabaseConfigured()) await supabase.from('announcements').insert(item);
    logActivity(`Added announcement: ${item.title}`);
  };

  const addTask = async (item: Task) => {
    setTasks([item, ...tasks]);
    if (isSupabaseConfigured()) await supabase.from('tasks').insert(item);
    logActivity(`Added task: ${item.title}`);
  };

  const toggleTaskCompletion = async (taskId: string) => {
    const task = tasks.find(t => t.id === taskId);
    if (!task) return;
    const newStatus = !task.isCompleted;

    setTasks(tasks.map(t => t.id === taskId ? { ...t, isCompleted: newStatus } : t));

    if (isSupabaseConfigured()) {
      await supabase.from('tasks').update({ isCompleted: newStatus }).eq('id', taskId);
    }
  };

  const addSubject = async (subject: Subject) => {
    setSubjects([...subjects, subject]);
    if (isSupabaseConfigured()) await supabase.from('subjects').insert(subject);
    logActivity(`Added subject: ${subject.name}`);
  }

  const deleteSubject = async (id: string) => {
    setSubjects(subjects.filter(s => s.id !== id));
    if (isSupabaseConfigured()) await supabase.from('subjects').delete().eq('id', id);
    logActivity(`Deleted subject ID: ${id}`);
  }

  const addScheduleItem = async (item: ScheduleItem) => {
    setSchedule([...schedule, item]);
    if (isSupabaseConfigured()) await supabase.from('schedule').insert(item);
    logActivity(`Added schedule item for ${item.day}`);
  }

  const deleteScheduleItem = async (id: string) => {
    setSchedule(schedule.filter(s => s.id !== id));
    if (isSupabaseConfigured()) await supabase.from('schedule').delete().eq('id', id);
    logActivity(`Deleted schedule item ID: ${id}`);
  }

  const addVideo = async (video: VideoMaterial) => {
    setVideos([video, ...videos]);
    if (isSupabaseConfigured()) await supabase.from('videos').insert(video);
    logActivity(`Added video: ${video.title}`);
  }

  const deleteVideo = async (id: string) => {
    setVideos(videos.filter(v => v.id !== id));
    if (isSupabaseConfigured()) await supabase.from('videos').delete().eq('id', id);
    logActivity(`Deleted video ID: ${id}`);
  }

  const addMaterial = async (material: DocumentMaterial) => {
    setMaterials([material, ...materials]);
    if (isSupabaseConfigured()) await supabase.from('materials').insert(material);
    logActivity(`Added material: ${material.title}`);
  }

  const deleteMaterial = async (id: string) => {
    setMaterials(materials.filter(m => m.id !== id));
    if (isSupabaseConfigured()) await supabase.from('materials').delete().eq('id', id);
    logActivity(`Deleted material ID: ${id}`);
  }

  const addTutorEvent = async (event: TutorEvent) => {
    setTutorEvents([event, ...tutorEvents]);
    if (isSupabaseConfigured()) await supabase.from('tutor_events').insert(event);
    logActivity(`Added tutor event: ${event.title}`);
  };

  const editTutorEvent = async (id: string, updates: Partial<TutorEvent>) => {
    setTutorEvents(prev => prev.map(ev => ev.id === id ? { ...ev, ...updates } : ev));
    if (isSupabaseConfigured()) await supabase.from('tutor_events').update(updates).eq('id', id);
    logActivity(`Edited tutor event ID: ${id}`);
  };

  const deleteTutorEvent = async (id: string) => {
    setTutorEvents(tutorEvents.filter(e => e.id !== id));
    if (isSupabaseConfigured()) await supabase.from('tutor_events').delete().eq('id', id);
    logActivity(`Deleted tutor event ID: ${id}`);
  };

  const joinTutorEvent = async (eventId: string) => {
    if (!currentUser) return;
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    // Check if already in participants or waiting list
    if (event.participants.includes(currentUser.id) || (event.waitingList && event.waitingList.includes(currentUser.id))) {
      return;
    }

    if (event.participants.length < event.maxParticipants) {
      // Join as participant
      const newParticipants = [...event.participants, currentUser.id];
      setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, participants: newParticipants } : ev));

      if (isSupabaseConfigured()) {
        await supabase.from('tutor_events').update({ participants: newParticipants }).eq('id', eventId);
      }
      logActivity(`Joined tutor event ID: ${eventId}`);
    } else {
      // Join waiting list
      const currentWaitingList = event.waitingList || [];
      const newWaitingList = [...currentWaitingList, currentUser.id];
      setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, waitingList: newWaitingList } : ev));

      if (isSupabaseConfigured()) {
        await supabase.from('tutor_events').update({ waitingList: newWaitingList }).eq('id', eventId);
      }
      logActivity(`Joined waiting list for event ID: ${eventId}`);
    }
  };

  const leaveTutorEvent = async (eventId: string) => {
    if (!currentUser) return;
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    const isParticipant = event.participants.includes(currentUser.id);
    const isWaitlisted = event.waitingList && event.waitingList.includes(currentUser.id);

    if (isParticipant) {
        const newParticipants = event.participants.filter(id => id !== currentUser.id);
        setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, participants: newParticipants } : ev));
        if (isSupabaseConfigured()) {
            await supabase.from('tutor_events').update({ participants: newParticipants }).eq('id', eventId);
        }
        logActivity(`Left tutor event ID: ${eventId}`);
    } else if (isWaitlisted) {
        const newWaitingList = (event.waitingList || []).filter(id => id !== currentUser.id);
        setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, waitingList: newWaitingList } : ev));
        if (isSupabaseConfigured()) {
            await supabase.from('tutor_events').update({ waitingList: newWaitingList }).eq('id', eventId);
        }
        logActivity(`Left waiting list for event ID: ${eventId}`);
    }
  };

  const promoteFromWaitingList = async (eventId: string, userId: string) => {
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    // Remove from waiting list
    const newWaitingList = (event.waitingList || []).filter(id => id !== userId);

    // Add to participants if not already there
    let newParticipants = event.participants;
    if (!event.participants.includes(userId)) {
       newParticipants = [...event.participants, userId];
    }

    setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { 
        ...ev, 
        waitingList: newWaitingList,
        participants: newParticipants
    } : ev));

    if (isSupabaseConfigured()) {
       await supabase.from('tutor_events').update({ 
           waitingList: newWaitingList,
           participants: newParticipants
       }).eq('id', eventId);
    }
    logActivity(`Promoted user ${userId} from waiting list in event ${eventId}`);
  };

  const assignUserToEvent = async (eventId: string, userId: string) => {
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    if (event.participants.includes(userId)) return;

    const newWaitingList = (event.waitingList || []).filter(id => id !== userId);
    const newParticipants = [...event.participants, userId];

    setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { 
        ...ev, 
        waitingList: newWaitingList,
        participants: newParticipants
    } : ev));

    if (isSupabaseConfigured()) {
       await supabase.from('tutor_events').update({ 
           waitingList: newWaitingList,
           participants: newParticipants
       }).eq('id', eventId);
    }
    logActivity(`Assigned user ${userId} to event ${eventId}`);
  };

  const kickFromEvent = async (eventId: string, userId: string) => {
    const event = tutorEvents.find(e => e.id === eventId);
    if (!event) return;

    const newParticipants = event.participants.filter(id => id !== userId);
    setTutorEvents(prev => prev.map(ev => ev.id === eventId ? { ...ev, participants: newParticipants } : ev));

    if (isSupabaseConfigured()) {
        await supabase.from('tutor_events').update({ participants: newParticipants }).eq('id', eventId);
    }
    logActivity(`Removed user ${userId} from event ${eventId}`);
  };

  const updateUserRole = async (userId: string, role: Role) => {
    setUsers(users.map(u => u.id === userId ? { ...u, role } : u));
    if (isSupabaseConfigured()) await supabase.from('users').update({ role }).eq('id', userId);
    logActivity(`Updated user ${userId} to role ${role}`);
  };

  const updateUserStatus = async (userId: string, isActive: boolean) => {
    setUsers(users.map(u => u.id === userId ? { ...u, isActive } : u));
    if (isSupabaseConfigured()) await supabase.from('users').update({ isActive }).eq('id', userId);
    logActivity(`Updated user ${userId} active status to ${isActive}`);
  };

  const updateUserProfile = async (userId: string, data: { fullName?: string, password?: string }) => {
    const updates: any = {};
    if (data.fullName) updates.fullName = data.fullName;
    if (data.password) updates.password = data.password;

    setUsers(users.map(u => {
      if (u.id === userId) {
        return { ...u, ...updates };
      }
      return u;
    }));

    if (currentUser && currentUser.id === userId) {
      const updatedUser = { ...currentUser, ...updates };
      setCurrentUser(updatedUser);
      // localStorage update handled by useEffect
    }

    if (isSupabaseConfigured()) await supabase.from('users').update(updates).eq('id', userId);
    logActivity(`User ${userId} updated their profile`);
  };

  const updateSeat = async (userId: string, seatIndex: number | null) => {
    setUsers(prev => prev.map(u => {
      if (u.id === userId) return { ...u, seatIndex };
      if (seatIndex !== null && u.seatIndex === seatIndex) return { ...u, seatIndex: null };
      return u;
    }));

    if (isSupabaseConfigured()) {
       if (seatIndex !== null) {
           await supabase.from('users').update({ seatIndex: null }).eq('seatIndex', seatIndex);
       }
       await supabase.from('users').update({ seatIndex }).eq('id', userId);
    }
    logActivity(`Updated seat for user ${userId}`);
  };

  const resetSeats = async () => {
     setUsers(prev => prev.map(u => ({ ...u, seatIndex: null })));
     if (isSupabaseConfigured()) await supabase.from('users').update({ seatIndex: null }).neq('id', '0');
     logActivity('Reset all seats');
  };

  const randomizeSeats = async () => {
    const students = users.filter(u => u.role === Role.STUDENT);
    const studentIds = students.map(u => u.id);
    const shuffled = [...studentIds].sort(() => Math.random() - 0.5);

    const updates = students.map(u => {
      const idx = shuffled.indexOf(u.id);
      return { id: u.id, seatIndex: idx < 35 ? idx : null };
    });

    setUsers(prev => prev.map(u => {
      if (u.role === Role.STUDENT) {
        const up = updates.find(x => x.id === u.id);
        return { ...u, seatIndex: up ? up.seatIndex : null };
      }
      return u;
    }));

    if (isSupabaseConfigured()) {
        for (const up of updates) {
            await supabase.from('users').update({ seatIndex: up.seatIndex }).eq('id', up.id);
        }
    }
    logActivity('Randomized seats');
  };

  return (
    <StoreContext.Provider value={{
      currentUser, users, subjects, announcements, tasks, schedule, videos, materials, tutorEvents, activityLog, isDarkMode, isLoading,
      toggleDarkMode, login, loginWithGoogle, logout, 
      addAnnouncement, addTask, toggleTaskCompletion,
      addSubject, deleteSubject, addScheduleItem, deleteScheduleItem,
      addVideo, deleteVideo,
      addMaterial, deleteMaterial,
      addTutorEvent, editTutorEvent, deleteTutorEvent, joinTutorEvent, leaveTutorEvent, promoteFromWaitingList, assignUserToEvent, kickFromEvent,
      updateUserRole, updateUserStatus, updateUserProfile,
      updateSeat, resetSeats, randomizeSeats
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error("useStore must be used within StoreProvider");
  return context;
};

