                  <ReactMarkdown 
                    remarkPlugins={[remarkMath, remarkGfm]} 
                    rehypePlugins={[rehypeKatex]}
                  >
                    {msg.text}
                  </ReactMarkdown>
                </div>
              </div>
            </div>
          ))}

          {isTyping && (
            <div className="flex justify-start w-full animate-pulse">
               <div className="bg-gray-100 dark:bg-gray-700 px-4 py-3 rounded-2xl rounded-tl-none flex items-center gap-1 shadow-sm border border-gray-200 dark:border-gray-600">
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-75"></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-150"></div>
               </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-gray-50 dark:bg-gray-900 border-t border-gray-200 dark:border-gray-700">
           {mode === 'quiz' && messages.length === 1 && (
              <div className="mb-2 text-xs text-center text-secondary animate-pulse">
                Type a topic to begin! (e.g. "Biology", "React JS", "History of Indonesia")
              </div>
           )}
           <form onSubmit={handleSend} className="relative flex items-center gap-2 max-w-4xl mx-auto w-full">
             <button 
                type="button" 
                onClick={() => startNewSession(mode)}
                className="p-3 text-gray-500 hover:text-red-500 hover:bg-gray-200 dark:hover:bg-gray-800 rounded-full transition-colors"
                title="Restart Session"
             >
                <RefreshCw size={20} />
             </button>
             <input 
               value={input}
               onChange={(e) => setInput(e.target.value)}
               placeholder={mode === 'quiz' ? "Type your answer or topic..." : "Ask me anything..."}
               className="flex-1 p-3 pl-4 pr-12 rounded-full border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent transition-all shadow-sm"
               disabled={isTyping}
             />
             <button 
               type="submit"
               disabled={!input.trim() || isTyping}
               className="absolute right-2 p-2 bg-primary text-white rounded-full hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
             >
               {isTyping ? <StopCircle size={20} className="animate-spin" /> : <Send size={20} />}
             </button>
           </form>
           <div className="text-center mt-2 text-[10px] text-gray-400">
              AI can make mistakes. Please verify important information.
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { useStore } from '../context/Store';
import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { BrainCircuit, Send, Sparkles, BookOpen, GraduationCap, RefreshCw, StopCircle } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import remarkGfm from 'remark-gfm';
import rehypeKatex from 'rehype-katex';

interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
}

const SYSTEM_INSTRUCTION_LEARN = `
You are ClassSync AI, a friendly, knowledgeable, and patient academic tutor. 
Your goal is to help students understand subjects like Math, Web Development, English, and Science.
Use LaTeX for math expressions where appropriate. IMPORTANT: Enclose inline math in single $ (e.g., $x^2$) and block math in $$ (e.g., $$E=mc^2$$).
Keep answers concise but informative. Use Markdown formatting (bold, lists, tables) to make it readable.
`;

const SYSTEM_INSTRUCTION_QUIZ = `
You are a Quiz Master. 
1. The user will provide a TOPIC.
2. You will generate ONE multiple-choice question at a time related to that topic.
3. The question must have 4 options (A, B, C, D).
4. Use LaTeX ($...$) for any math symbols.
5. Wait for the user to answer.
6. Provide immediate feedback (Correct/Incorrect) and a brief explanation using LaTeX if needed.
7. IMMEDIATELY ask the NEXT question.
`;

export const AiTutor = () => {
  const { currentUser } = useStore();
  const [mode, setMode] = useState<'learn' | 'quiz'>('learn');
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isTyping, setIsTyping] = useState(false);
  const [chatSession, setChatSession] = useState<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    startNewSession(mode);
  }, [mode]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  const startNewSession = (selectedMode: 'learn' | 'quiz') => {
    setMessages([]);

    if (!process.env.API_KEY) {
       setMessages([{
         id: 'error',
         role: 'model',
         text: 'Error: API_KEY is missing. Please configure it in your environment variables.'
       }]);
       return;
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: selectedMode === 'quiz' ? SYSTEM_INSTRUCTION_QUIZ : SYSTEM_INSTRUCTION_LEARN,
        },
      });
      setChatSession(chat);

      const initialText = selectedMode === 'quiz' 
        ? "I am ready! Please type a **Topic** to start the quiz (e.g., 'Calculus', 'History', 'Physics')." 
        : `Hi ${currentUser?.fullName.split(' ')[0]}! I'm your AI Tutor. What subject are we studying today?`;

      setMessages([{
        id: 'init',
        role: 'model',
        text: initialText
      }]);

    } catch (error) {
      console.error("Failed to init Gemini:", error);
    }
  };

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || !chatSession || isTyping) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const response: GenerateContentResponse = await chatSession.sendMessage({ message: userMsg.text });
      const text = response.text || "Sorry, I couldn't generate a response.";

      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: text
      }]);
    } catch (error) {
      console.error("Gemini Error:", error);
      setMessages(prev => [...prev, {
        id: Date.now().toString(),
        role: 'model',
        text: "⚠️ Connection error. Please try again."
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="h-[calc(100vh-2rem)] flex flex-col p-4 md:p-6 max-w-6xl mx-auto w-full">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-4 gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <BrainCircuit className="text-primary" /> AI Tutor
          </h1>
          <p className="text-sm text-gray-500 dark:text-gray-400">Powered by Google Gemini</p>
        </div>

        <div className="flex bg-gray-200 dark:bg-gray-800 p-1 rounded-lg self-start md:self-auto">
          <button
            onClick={() => setMode('learn')}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm font-medium transition-all ${
              mode === 'learn' 
                ? 'bg-white dark:bg-gray-700 text-primary shadow-sm' 
                : 'text-gray-600 dark:text-gray-400 hover:text-gray-900'
            }`}
          >
            <BookOpen size={16} /> Learn
          </button>
          <button
            onClick={() => setMode('quiz')}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm font-medium transition-all ${
              mode === 'quiz' 
                ? 'bg-white dark:bg-gray-700 text-secondary shadow-sm' 
                : 'text-gray-600 dark:text-gray-400 hover:text-gray-900'
            }`}
          >
            <GraduationCap size={16} /> Quiz
          </button>
        </div>
      </div>

      {/* Chat Container */}
      <div className="flex-1 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden flex flex-col relative">

        {/* Messages Area */}
        <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar bg-gray-50/50 dark:bg-gray-900/50">
          {messages.map((msg) => (
            <div 
              key={msg.id} 
              className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div 
                className={`flex flex-col max-w-[90%] md:max-w-[75%] lg:max-w-[70%] min-w-0 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}
              >
                {msg.role === 'model' && (
                  <div className="flex items-center gap-2 mb-1 text-xs opacity-70 font-bold uppercase tracking-wider select-none text-gray-500 dark:text-gray-400 px-1">
                     {mode === 'quiz' ? <Sparkles size={12} /> : <BrainCircuit size={12} />}
                     {mode === 'quiz' ? 'Quiz Master' : 'AI Tutor'}
                  </div>
                )}

                <div 
                  className={`p-4 rounded-2xl shadow-sm overflow-hidden w-full ${
                    msg.role === 'user' 
                      ? 'bg-primary text-white rounded-tr-none' 
                      : 'bg-white dark:bg-gray-700 text-gray-800 dark:text-gray-100 rounded-tl-none border border-gray-200 dark:border-gray-600'
                  }`}
                >
                  <div className={`text-sm md:text-base markdown-content ${msg.role === 'user' ? 'user-message' : ''}`}>
                    <ReactMarkdown 
                      remarkPlugins={[remarkMath, remarkGfm]} 
                      rehypePlugins={[rehypeKatex]}
                      components={{
                        // Handle tables with horizontal scroll to prevent breaking layout
                        table: ({node, ...props}) => (
                          <div className="overflow-x-auto my-4 border rounded border-gray-200 dark:border-gray-600">
                             <table {...props} className="w-full" />
                          </div>
                        ),
                        // Ensure links open in new tab
                        a: ({node, ...props}) => <a {...props} target="_blank" rel="noopener noreferrer" />
                      }}
                    >
                      {msg.text}
                    </ReactMarkdown>
                  </div>
                </div>
              </div>
            </div>
          ))}

          {isTyping && (
            <div className="flex justify-start w-full">
               <div className="bg-white dark:bg-gray-700 px-4 py-3 rounded-2xl rounded-tl-none border border-gray-200 dark:border-gray-600 flex items-center gap-1">
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-75"></div>
                  <div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-150"></div>
               </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-white dark:bg-gray-800 border-t border-gray-200 dark:border-gray-700">
           {mode === 'quiz' && messages.length === 1 && (
              <div className="mb-2 text-xs text-center text-secondary animate-pulse">
                Type a topic to begin! (e.g. "Biology", "React JS")
              </div>
           )}
           <form onSubmit={handleSend} className="relative flex items-center gap-2">
             <button 
                type="button" 
                onClick={() => startNewSession(mode)}
                className="p-3 text-gray-500 hover:text-red-500 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"
                title="Restart Session"
             >
                <RefreshCw size={20} />
             </button>
             <input 
               value={input}
               onChange={(e) => setInput(e.target.value)}
               placeholder={mode === 'quiz' ? "Type your answer or topic..." : "Ask me anything..."}
               className="flex-1 p-3 pl-4 pr-12 rounded-full border border-gray-300 dark:border-gray-600 bg-gray-50 dark:bg-gray-900 text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent transition-all shadow-sm"
               disabled={isTyping}
             />
             <button 
               type="submit"
               disabled={!input.trim() || isTyping}
               className="absolute right-2 p-2 bg-primary text-white rounded-full hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
             >
               {isTyping ? <StopCircle size={20} className="animate-spin" /> : <Send size={20} />}
             </button>
           </form>
           <div className="text-center mt-2 text-[10px] text-gray-400">
              AI can make mistakes. Please verify important information.
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useStore } from '../context/Store';
import { Role } from '../types';
import { Video, Plus, Trash2 } from 'lucide-react';

export const Videos = () => {
  const { videos, subjects, currentUser, addVideo, deleteVideo } = useStore();
  const [showModal, setShowModal] = useState(false);
  const [filterSubject, setFilterSubject] = useState('ALL');

  const [newVideo, setNewVideo] = useState({ title: '', url: '', subject: '', week: 1 });

  const canAdd = [Role.IT_LOGISTIK, Role.KURIKULUM, Role.ADMIN].includes(currentUser?.role as Role);

  const getEmbedUrl = (url: string) => {
    // Regex to extract Video ID from various YouTube URL formats
    // Supports: Standard watch, Short links (youtu.be), Shorts, Live, Embeds
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=|shorts\/|live\/)([^#&?]*).*/;
    const match = url.match(regExp);

    if (match && match[2].length === 11) {
        return `https://www.youtube.com/embed/${match[2]}`;
    }

    // Fallback if regex doesn't match (e.g. maybe it's already an embed link or non-youtube)
    return url;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    const finalUrl = getEmbedUrl(newVideo.url);

    addVideo({
      id: Date.now().toString(),
      title: newVideo.title,
      url: finalUrl,
      subject: newVideo.subject,
      week: Number(newVideo.week),
      uploadedBy: currentUser.role
    });
    setShowModal(false);
    setNewVideo({ title: '', url: '', subject: '', week: 1 });
  };

  const filteredVideos = filterSubject === 'ALL' 
    ? videos 
    : videos.filter(v => v.subject === filterSubject);

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
          <Video /> Class Videos
        </h1>
        {canAdd && (
          <button 
            onClick={() => setShowModal(true)}
            className="bg-primary text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-600"
          >
            <Plus size={18} /> Add Video
          </button>
        )}
      </div>

      <div className="mb-6">
        <select 
          value={filterSubject}
          onChange={(e) => setFilterSubject(e.target.value)}
          className="p-2 border rounded-lg bg-white dark:bg-gray-800 dark:text-white dark:border-gray-700"
        >
          <option value="ALL">All Subjects</option>
          {subjects.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
        </select>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredVideos.map(video => (
          <div key={video.id} className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden group">
            <div className="aspect-video bg-gray-100 dark:bg-gray-900 relative">
              <iframe 
                src={video.url} 
                className="w-full h-full" 
                title={video.title} 
                allowFullScreen
                loading="lazy"
              />
            </div>
            <div className="p-4">
              <div className="flex justify-between items-start mb-2">
                 <span className="text-xs font-semibold bg-gray-100 dark:bg-gray-700 px-2 py-1 rounded text-gray-600 dark:text-gray-300">
                    Week {video.week}
                 </span>
                 {canAdd && (
                   <button 
                     onClick={() => deleteVideo(video.id)}
                     className="text-gray-400 hover:text-red-500"
                   >
                     <Trash2 size={16} />
                   </button>
                 )}
              </div>
              <h3 className="font-bold text-lg text-gray-900 dark:text-white line-clamp-1">{video.title}</h3>
              <p className="text-sm text-primary mt-1">{video.subject}</p>
              <div className="mt-3 text-xs text-gray-400 flex items-center gap-1">
                 Uploaded by {video.uploadedBy}
              </div>
            </div>
          </div>
        ))}
      </div>

      {filteredVideos.length === 0 && (
        <div className="text-center py-12 text-gray-400">No videos found.</div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white dark:bg-gray-800 p-6 rounded-lg w-full max-w-md">
            <h3 className="text-xl font-bold mb-4 dark:text-white">Add Video Material</h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <input 
                className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                placeholder="Video Title"
                required
                value={newVideo.title}
                onChange={e => setNewVideo({...newVideo, title: e.target.value})}
              />
              <div className="space-y-1">
                <input 
                    className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                    placeholder="YouTube URL (Shorts/Live/Watch)"
                    required
                    value={newVideo.url}
                    onChange={e => setNewVideo({...newVideo, url: e.target.value})}
                />
                <p className="text-[10px] text-gray-400">Supports: Standard, Shorts, Unlisted, & Share links.</p>
              </div>
              <select 
                className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                required
                value={newVideo.subject}
                onChange={e => setNewVideo({...newVideo, subject: e.target.value})}
              >
                <option value="">Select Subject</option>
                {subjects.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
              </select>
              <input 
                type="number"
                min="1"
                className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                placeholder="Week Number"
                required
                value={newVideo.week}
                onChange={e => setNewVideo({...newVideo, week: Number(e.target.value)})}
              />
              <div className="flex justify-end gap-2">
                <button type="button" onClick={() => setShowModal(false)} className="px-4 py-2 text-gray-500">Cancel</button>
                <button type="submit" className="px-4 py-2 bg-primary text-white rounded">Save</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useStore } from '../context/Store';
import { Role } from '../types';
import { Video, Plus, Trash2, AlertCircle } from 'lucide-react';

export const Videos = () => {
  const { videos, subjects, currentUser, addVideo, deleteVideo } = useStore();
  const [showModal, setShowModal] = useState(false);
  const [filterSubject, setFilterSubject] = useState('ALL');

  const [newVideo, setNewVideo] = useState({ title: '', url: '', subject: '', week: 1 });

  const canAdd = [Role.IT_LOGISTIK, Role.KURIKULUM, Role.ADMIN].includes(currentUser?.role as Role);

  const getEmbedUrl = (url: string) => {
    // 1. Handle Google Drive (Commonly confused with "Private link")
    // Converts /view or /edit links to /preview for embedding
    if (url.includes('drive.google.com') && (url.includes('/view') || url.includes('/edit'))) {
       return url.replace(/\/view.*|\/edit.*/, '/preview');
    }

    // 2. Handle YouTube (Standard, Shorts, Live, Unlisted)
    // Regex to extract Video ID from various YouTube URL formats
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=|shorts\/|live\/)([^#&?]*).*/;
    const match = url.match(regExp);

    if (match && match[2]) {
        // ID is usually 11 chars. We allow 10-12 to be safe.
        if (match[2].length >= 10) {
            return `https://www.youtube.com/embed/${match[2]}`;
        }
    }

    // Fallback if regex doesn't match (e.g. maybe it's already an embed link or non-youtube)
    return url;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    const finalUrl = getEmbedUrl(newVideo.url);

    addVideo({
      id: Date.now().toString(),
      title: newVideo.title,
      url: finalUrl,
      subject: newVideo.subject,
      week: Number(newVideo.week),
      uploadedBy: currentUser.role
    });
    setShowModal(false);
    setNewVideo({ title: '', url: '', subject: '', week: 1 });
  };

  const filteredVideos = filterSubject === 'ALL' 
    ? videos 
    : videos.filter(v => v.subject === filterSubject);

  return (
    <div className="p-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
          <Video /> Class Videos
        </h1>
        {canAdd && (
          <button 
            onClick={() => setShowModal(true)}
            className="bg-primary text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-blue-600"
          >
            <Plus size={18} /> Add Video
          </button>
        )}
      </div>

      <div className="mb-6">
        <select 
          value={filterSubject}
          onChange={(e) => setFilterSubject(e.target.value)}
          className="p-2 border rounded-lg bg-white dark:bg-gray-800 dark:text-white dark:border-gray-700 focus:ring-2 focus:ring-primary outline-none"
        >
          <option value="ALL">All Subjects</option>
          {subjects.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
        </select>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredVideos.map(video => (
          <div key={video.id} className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden group">
            <div className="aspect-video bg-gray-100 dark:bg-gray-900 relative">
              <iframe 
                src={video.url} 
                className="w-full h-full" 
                title={video.title} 
                allowFullScreen
                loading="lazy"
              />
            </div>
            <div className="p-4">
              <div className="flex justify-between items-start mb-2">
                 <span className="text-xs font-semibold bg-gray-100 dark:bg-gray-700 px-2 py-1 rounded text-gray-600 dark:text-gray-300">
                    Week {video.week}
                 </span>
                 {canAdd && (
                   <button 
                     onClick={() => deleteVideo(video.id)}
                     className="text-gray-400 hover:text-red-500 transition-colors"
                     title="Delete Video"
                   >
                     <Trash2 size={16} />
                   </button>
                 )}
              </div>
              <h3 className="font-bold text-lg text-gray-900 dark:text-white line-clamp-1">{video.title}</h3>
              <p className="text-sm text-primary mt-1">{video.subject}</p>
              <div className="mt-3 text-xs text-gray-400 flex items-center gap-1">
                 Uploaded by {video.uploadedBy}
              </div>
            </div>
          </div>
        ))}
      </div>

      {filteredVideos.length === 0 && (
        <div className="text-center py-12 text-gray-400">No videos found.</div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white dark:bg-gray-800 p-6 rounded-xl w-full max-w-md shadow-2xl">
            <h3 className="text-xl font-bold mb-4 dark:text-white">Add Video Material</h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
